import type { setupConditionModeSwitchBindings } from './setup'

interface CreateConditionModeSwitchExposedBindingsOptions {
  setupResult: ReturnType<typeof setupConditionModeSwitchBindings>
}

export function createConditionModeSwitchExposedBindings(
  options: CreateConditionModeSwitchExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    negationToggleListeners: setupResult.negationToggleListeners,
    modeRadioListeners: setupResult.modeRadioListeners,
  }
}
