import { computed } from 'vue'
import type { FunctionRefEditorProps } from './types'

interface FunctionRefEditorState {
  hasSelectedFunction: { value: boolean }
  showParameters: { value: boolean }
}

export function createFunctionRefEditorViewModel(
  props: FunctionRefEditorProps,
  state: FunctionRefEditorState,
) {
  const selectorProps = computed(() => ({
    modelValue: props.selectedFunctionName,
    categories: props.functionCategories,
  }))

  const parameterProps = computed(() => ({
    parameters: props.functionParameters,
    availableFields: props.availableFields,
  }))

  const previewProps = computed(() => ({
    expression: props.functionExpression,
  }))

  return {
    hasSelectedFunction: state.hasSelectedFunction,
    showParameters: state.showParameters,
    selectorProps,
    parameterProps,
    previewProps,
  }
}
