import type { createParameterInputNestedActions } from './useParameterInputController.actions.nested'
import type { createParameterInputValueActions } from './useParameterInputController.actions.value'

interface CreateParameterInputControllerActionsExposedOptions {
  valueActions: ReturnType<typeof createParameterInputValueActions>
  nestedActions: ReturnType<typeof createParameterInputNestedActions>
}

export function createParameterInputControllerActionsExposed(
  options: CreateParameterInputControllerActionsExposedOptions,
) {
  const { valueActions, nestedActions } = options

  return {
    initializeLambdaParameter: valueActions.initializeLambdaParameter,
    updateValue: valueActions.updateValue,
    updateMultiValue: valueActions.updateMultiValue,
    updateFormatValue: valueActions.updateFormatValue,
    updateTimezoneValue: valueActions.updateTimezoneValue,
    changeValueDataType: valueActions.changeValueDataType,
    changeParameterType: valueActions.changeParameterType,
    updateNestedNode: nestedActions.updateNestedNode,
    updateNestedParameterType: nestedActions.updateNestedParameterType,
  }
}
