import { watch } from 'vue'
import type { ValueInputControllerState } from './useValueInputController.shared'
import type { ValueInputProps } from './useValueInputController.types'

interface RegisterValueInputControllerWatchersOptions {
  props: ValueInputProps
  state: ValueInputControllerState
}

export function registerValueInputControllerWatchers(
  options: RegisterValueInputControllerWatchersOptions,
): void {
  const { props, state } = options

  watch(
    () => props.value,
    () => {
      state.syncFunctionStateFromValue()
    },
    { immediate: true },
  )
}
