import type {
  UseValueInputControllerActionsOptions,
  ValueInputControllerState,
} from './useValueInputController.shared'
import { createValueInputControllerActionsExposed } from './useValueInputController.actions.exposed'
import { useValueInputControllerFieldActions } from './useValueInputController.fieldActions'
import { useValueInputControllerFunctionActions } from './useValueInputController.functionActions'
import { useValueInputControllerTypeActions } from './useValueInputController.typeActions'
import { useValueInputControllerValueActions } from './useValueInputController.valueActions'

export function useValueInputControllerActions(
  state: ValueInputControllerState,
  options: UseValueInputControllerActionsOptions,
) {
  const valueActions = useValueInputControllerValueActions(state, options)
  const typeActions = useValueInputControllerTypeActions(state, options)
  const fieldActions = useValueInputControllerFieldActions(state, options)
  const functionActions = useValueInputControllerFunctionActions(state, options)

  return createValueInputControllerActionsExposed({
    valueActions,
    typeActions,
    fieldActions,
    functionActions,
  })
}
