import { createConditionNodeViewExposedBindings } from './view-bindings/exposed'
import { setupConditionNodeViewBindings } from './view-bindings/setup'
import type {
  UseConditionNodeViewBindingsOptions,
} from './view-bindings/types'

export type {
  ConditionNodeViewEmits,
  ConditionNodeViewProps,
  UseConditionNodeViewBindingsOptions,
} from './view-bindings/types'

export function useConditionNodeViewBindings(options: UseConditionNodeViewBindingsOptions) {
  const setupResult = setupConditionNodeViewBindings(options)
  return createConditionNodeViewExposedBindings({ setupResult })
}
