import { createFunctionRefEditorForwarders } from './forwarders'
import { createFunctionRefEditorListeners } from './listeners'
import { createFunctionRefEditorState } from './state'
import { createFunctionRefEditorViewModel } from './viewModel'
import type { FunctionRefEditorEmits, FunctionRefEditorProps } from './types'

interface SetupFunctionRefEditorBindingsOptions {
  props: FunctionRefEditorProps
  emit: FunctionRefEditorEmits
}

export function setupFunctionRefEditorBindings(options: SetupFunctionRefEditorBindingsOptions) {
  const { props, emit } = options

  const state = createFunctionRefEditorState(props)
  const forwarders = createFunctionRefEditorForwarders(emit)
  const listeners = createFunctionRefEditorListeners({ forwarders })
  const viewModel = createFunctionRefEditorViewModel(props, state)

  return {
    listeners,
    viewModel,
  }
}
