import { computed } from 'vue'
import type { ValueInputSwitchPanelProps } from '../switch-panel/types'
import { createValueInputSwitchPanelBaseProps } from './panel-props.base'
import { createValueInputSwitchPanelComposedProps } from './panel-props.compose'
import { createValueInputSwitchPanelFunctionProps } from './panel-props.function'
import type { CreateValueInputSwitchPanelPropsOptions } from './panel-props.types'

export function createValueInputSwitchPanelProps(options: CreateValueInputSwitchPanelPropsOptions) {
  return computed<ValueInputSwitchPanelProps>(() => {
    const baseProps = createValueInputSwitchPanelBaseProps(options)
    const functionProps = createValueInputSwitchPanelFunctionProps(options)

    return createValueInputSwitchPanelComposedProps({
      baseProps,
      functionProps,
    })
  })
}
