import type { setupFunctionRefParameterItemBindings } from './item.setup'

interface CreateFunctionRefParameterItemExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionRefParameterItemBindings>
}

export function createFunctionRefParameterItemExposedBindings(
  options: CreateFunctionRefParameterItemExposedBindingsOptions,
) {
  const { panelProps, listeners } = options.setupResult

  return {
    labelProps: panelProps.labelProps,
    inputBodyProps: panelProps.inputBodyProps,
    inputBodyListeners: listeners.inputBodyListeners,
  }
}
