import { computed, ref } from 'vue'
import { buildFunctionCategories, findFunctionByName } from '../../logic/value-input'
import { createFunctionRefValueActions } from './actions'
import { createFunctionRefValueControllerExposed } from './exposed'
import type { FunctionRefParameter, UseFunctionRefValueControllerOptions } from './types'

export type { FunctionRefParameter, UseFunctionRefValueControllerOptions } from './types'

export function useFunctionRefValueController(options: UseFunctionRefValueControllerOptions) {
  const { functions } = options

  const selectedFunctionName = ref('')
  const functionParameters = ref<FunctionRefParameter[]>([])

  const functionCategories = computed(() => buildFunctionCategories(functions))

  const selectedFunction = computed(() => {
    if (!selectedFunctionName.value) {
      return null
    }
    return findFunctionByName(selectedFunctionName.value, functions)
  })

  const actions = createFunctionRefValueActions({
    functions,
    selectedFunctionName,
    functionParameters,
    selectedFunction,
  })

  return createFunctionRefValueControllerExposed({
    selectedFunctionName,
    functionParameters,
    functionCategories,
    selectedFunction,
    actions,
  })
}

export type FunctionRefValueController = ReturnType<typeof useFunctionRefValueController>
