import { computed } from 'vue'
import { useTreeExpressionBuilderController } from '../../composables/useTreeExpressionBuilderController'
import { createTreeExpressionBuilderListeners } from './listeners'
import type { UseTreeExpressionBuilderBindingsOptions } from './types'

export function setupTreeExpressionBuilderBindings(options: UseTreeExpressionBuilderBindingsOptions) {
  const { props, emit } = options

  const controller = useTreeExpressionBuilderController({
    props,
    emitUpdateModelValue: (value) => emit('update:modelValue', value),
  })
  const listeners = createTreeExpressionBuilderListeners({ controller })
  const hasDataPreview = computed(() => Boolean(props.dataPreview))

  return {
    controller,
    listeners,
    hasDataPreview,
  }
}
