import { h } from 'vue'
import type { AviatorFunction } from '../../infrastructure/engine/types'

export function renderParameterList(func: AviatorFunction) {
  if (func.parameters.length === 0) {
    return [h('span', { style: { color: '#86909c', fontStyle: 'italic', fontSize: '12px' } }, '无参数')]
  }

  return func.parameters.map((param) =>
    h('div', { class: 'usage-param-item', style: { marginBottom: '8px' } }, [
      h('span', { style: { fontFamily: 'Consolas, Monaco, monospace', color: '#165dff', fontWeight: 500 } }, param.name),
      h('span', { style: { color: '#86909c', fontSize: '11px', marginLeft: '4px' } }, `(${param.type})`),
      param.required ? h('span', { style: { color: '#f53f3f', fontSize: '11px', marginLeft: '4px' } }, '*必填') : null,
      h('span', { style: { color: '#4e5969', marginLeft: '6px' } }, `- ${param.description}`),
    ]),
  )
}
