import type { GroupChildNodeType } from '../../../types/treeInteraction'
import type { TreeNodeContentEmits } from './types'

export function createTreeNodeContentActionBindings(emit: TreeNodeContentEmits) {
  const onAddChild = (parentId: string, nodeType: GroupChildNodeType) => emit('add-child', parentId, nodeType)
  const onMoveUp = (nodeId: string) => emit('move-up', nodeId)
  const onMoveDown = (nodeId: string) => emit('move-down', nodeId)
  const onCopyNode = () => emit('copy-node')
  const onRemoveNode = (nodeId: string) => emit('remove-node', nodeId)

  return {
    onAddChild,
    onMoveUp,
    onMoveDown,
    onCopyNode,
    onRemoveNode,
  }
}
