import type { AviatorFunction } from '../../../infrastructure/engine/types'

export interface FunctionCategory {
  name: string
  label: string
  functions: AviatorFunction[]
}

export function buildFunctionCategories(functions: readonly AviatorFunction[]): FunctionCategory[] {
  const categories: Record<string, FunctionCategory> = {
    system: { name: 'system', label: '系统函数', functions: [] },
    string: { name: 'string', label: '字符串函数', functions: [] },
    math: { name: 'math', label: '数学函数', functions: [] },
    sequence: { name: 'sequence', label: '集合函数', functions: [] },
    datetime: { name: 'datetime', label: '日期时间函数', functions: [] },
    custom: { name: 'custom', label: '安全检查函数', functions: [] },
  }

  functions.forEach((func) => {
    if (categories[func.category]) {
      categories[func.category].functions.push(func)
    }
  })

  return Object.values(categories).filter((category) => category.functions.length > 0)
}
