import type { FunctionComparisonPanelEmits, FunctionComparisonPanelListeners } from './types'

interface CreateFunctionComparisonPanelListenersOptions {
  emit: FunctionComparisonPanelEmits
}

export function createFunctionComparisonPanelListeners(
  options: CreateFunctionComparisonPanelListenersOptions,
): FunctionComparisonPanelListeners {
  const { emit } = options

  return {
    comparisonOperatorListeners: {
      'update:model-value': (value: string) => emit('update:comparison', value),
    },
    comparisonValueInputListeners: {
      'update:value': (value) => emit('update:value', value),
      'update:value-data-type': (data) => emit('update:value-data-type', data),
    },
  }
}
