import { createValueInputForwarders } from '../switch-panel/value-input-forwarders'
import { createValueInputSwitchPanelListeners } from './listeners'
import { createValueInputSwitchPanelPanelProps } from './panelProps'
import type { UseValueInputSwitchPanelBindingsOptions } from './types'

export function setupValueInputSwitchPanelBindings(options: UseValueInputSwitchPanelBindingsOptions) {
  const forwarders = createValueInputForwarders(options.emit)
  const listeners = createValueInputSwitchPanelListeners(forwarders)
  const panelProps = createValueInputSwitchPanelPanelProps({ props: options.props })

  return {
    panelProps,
    listeners,
  }
}
