import type { createFunctionRefEditorForwarders } from './forwarders'

interface CreateFunctionRefEditorListenersOptions {
  forwarders: ReturnType<typeof createFunctionRefEditorForwarders>
}

export function createFunctionRefEditorListeners(options: CreateFunctionRefEditorListenersOptions) {
  const { forwarders } = options

  const selectorListeners = {
    'update:model-value': forwarders.onUpdateFunction,
  } as const

  const parameterListeners = {
    'update:parameter': forwarders.onUpdateParameter,
  } as const

  return {
    selectorListeners,
    parameterListeners,
  }
}
