import type { FunctionParameterUpdatePayload } from '../types'
import type { UseFunctionRefParametersBindingsOptions } from './types'

export function setupFunctionRefParametersBindings(options: UseFunctionRefParametersBindingsOptions) {
  const onUpdateParameterPayload = (payload: FunctionParameterUpdatePayload) => {
    options.emit('update:parameter', payload)
  }

  return {
    onUpdateParameterPayload,
  }
}
