<template>
  <ConditionBooleanSelect
    v-if="valueDataType === 'boolean'"
    :model-value="resolvedDisplayValue"
    v-on="valueListeners"
  />

  <ParameterTextValueInput
    v-else
    :model-value="resolvedDisplayValue"
    v-on="valueListeners"
  />
</template>

<script setup lang="ts">
import type { NodeValue } from '../../../../../../infrastructure/engine/types'
import ConditionBooleanSelect from '../../condition-value/ConditionBooleanSelect.vue'
import ParameterTextValueInput from '../ParameterTextValueInput.vue'

defineProps<{
  resolvedDisplayValue: NodeValue
  valueDataType: string
}>()

const emit = defineEmits<{
  (e: 'update:value', value: NodeValue): void
}>()

const valueListeners = {
  'update:model-value': (value: NodeValue) => emit('update:value', value),
} as const
</script>
