import type { ParameterInputProps } from './useParameterInputController.types'
import { createParameterInputControllerDisplayValue } from './useParameterInputController.state.computed'
import { createParameterInputControllerStateExposed } from './useParameterInputController.state.exposed'
import { createParameterInputControllerStateQueries } from './useParameterInputController.state.queries'
import { createParameterInputControllerStateRefs } from './useParameterInputController.state.refs'

export interface UseParameterInputControllerStateOptions {
  props: ParameterInputProps
}

export function useParameterInputControllerState(options: UseParameterInputControllerStateOptions) {
  const { props } = options

  const refs = createParameterInputControllerStateRefs()
  const displayValue = createParameterInputControllerDisplayValue(props)
  const queries = createParameterInputControllerStateQueries({
    props,
    refs,
    displayValue,
  })

  return createParameterInputControllerStateExposed({
    refs,
    displayValue,
    queries,
  })
}
