import type { UseConditionModeSwitchBindingsOptions } from './types'

export function setupConditionModeSwitchBindings(options: UseConditionModeSwitchBindingsOptions) {
  const { emit } = options

  const negationToggleListeners = {
    'update:model-value': (value: boolean) => emit('update:negation', value),
  } as const

  const modeRadioListeners = {
    'update:model-value': (mode: 'condition' | 'function') => emit('switch:mode', mode),
  } as const

  return {
    negationToggleListeners,
    modeRadioListeners,
  }
}
