import type { createTreeNodeViewForwarders } from '../useTreeNodeViewBindings.forwarders'

export function createTreeNodeChildrenListeners(
  forwarders: ReturnType<typeof createTreeNodeViewForwarders>,
) {
  return {
    'update-node': forwarders.forwardUpdateNode,
    'add-child': forwarders.forwardAddChild,
    'remove-node': forwarders.forwardRemoveNode,
    'move-up': forwarders.forwardMoveUp,
    'move-down': forwarders.forwardMoveDown,
    'copy-node': forwarders.forwardCopyNode,
    'update-parameter-type': forwarders.forwardUpdateParameterType,
    'update-parameter-value-data-type': forwarders.forwardUpdateParameterValueDataType,
    'drag-node': forwarders.forwardDragNode,
  } as const
}
