import type { ValueInputSwitchPanelProps } from '../switch-panel/types'
import type { createValueInputSwitchPanelBaseProps } from './panel-props.base'
import type { createValueInputSwitchPanelFunctionProps } from './panel-props.function'

interface CreateValueInputSwitchPanelComposedPropsOptions {
  baseProps: ReturnType<typeof createValueInputSwitchPanelBaseProps>
  functionProps: ReturnType<typeof createValueInputSwitchPanelFunctionProps>
}

export function createValueInputSwitchPanelComposedProps(
  options: CreateValueInputSwitchPanelComposedPropsOptions,
): ValueInputSwitchPanelProps {
  const { baseProps, functionProps } = options

  return {
    currentInputType: baseProps.currentInputType,
    valueTypeOptions: baseProps.valueTypeOptions,
    value: baseProps.value,
    fieldType: baseProps.fieldType,
    comparison: baseProps.comparison,
    availableFields: baseProps.availableFields,
    valueDataType: baseProps.valueDataType,
    placeholder: baseProps.placeholder,
    multiValues: baseProps.multiValues,
    dateValue: baseProps.dateValue,
    urlError: baseProps.urlError,
    valueArrayIndex: baseProps.valueArrayIndex,
    getFieldTypeColor: baseProps.getFieldTypeColor,
    getFieldTooltip: baseProps.getFieldTooltip,
    selectedFunctionName: functionProps.selectedFunctionName,
    functionCategories: functionProps.functionCategories,
    selectedFunction: functionProps.selectedFunction,
    functionParameters: functionProps.functionParameters,
    functionExpression: functionProps.functionExpression,
  }
}
