import { createTreeNodeListeners } from '../../shared/tree-node-events'
import type { createTreeCanvasGroupForwarders } from './group-forwarders'
import type { createTreeCanvasNodeForwarders } from './node-forwarders'

interface CreateTreeCanvasListenersOptions {
  nodeForwarders: ReturnType<typeof createTreeCanvasNodeForwarders>
  groupForwarders: ReturnType<typeof createTreeCanvasGroupForwarders>
}

export function createTreeCanvasListeners(options: CreateTreeCanvasListenersOptions) {
  const { nodeForwarders, groupForwarders } = options
  const { treeNodeListeners } = createTreeNodeListeners({
    forwarders: nodeForwarders,
  })

  const emptyStateButtonListeners = {
    click: groupForwarders.onAddGroup,
  }

  return {
    nodeListeners: treeNodeListeners,
    emptyStateButtonListeners,
  }
}
