import { useTreeNodeController } from '../../../composables/useTreeNodeController'
import type { TreeNodeViewEmits, TreeNodeViewProps } from '../types'

export function createTreeNodeControllerBindings(props: TreeNodeViewProps, emit: TreeNodeViewEmits) {
  return useTreeNodeController({
    props,
    emitUpdateNode: (nodeId, updates) => emit('update-node', nodeId, updates),
    emitCopyNode: (nodeId) => emit('copy-node', nodeId),
    emitUpdateParameterType: (paramName, type) => emit('update-parameter-type', paramName, type),
    emitUpdateParameterValueDataType: (nodeId, paramName, dataType) => emit('update-parameter-value-data-type', nodeId, paramName, dataType),
    emitDragNode: (sourceNodeId, targetNodeId, position) => emit('drag-node', sourceNodeId, targetNodeId, position),
  })
}
