import { computed } from 'vue'
import type { ParameterValueInputSwitchProps } from './types'

export function createParameterValueInputSwitchPanelProps(props: ParameterValueInputSwitchProps) {
  const formatSelectProps = computed(() => ({
    modelValue: props.resolvedDisplayValue,
  }))

  const timezoneSelectProps = computed(() => ({
    modelValue: props.resolvedDisplayValue,
  }))

  const multiValueInputProps = computed(() => ({
    modelValue: props.multiValues,
    placeholder: props.multiValuePlaceholder,
  }))

  const fallbackInputProps = computed(() => ({
    resolvedDisplayValue: props.resolvedDisplayValue,
    valueDataType: props.valueDataType,
  }))

  return {
    formatSelectProps,
    timezoneSelectProps,
    multiValueInputProps,
    fallbackInputProps,
  }
}
