import { createValueEditorListeners } from './listeners'
import { createValueEditorPanelProps } from './props'
import { createValueEditorState } from './state'
import type { ValueEditorEmits, ValueEditorProps } from './types'

export interface SetupValueEditorBindingsOptions {
  props: ValueEditorProps
  emit: ValueEditorEmits
}

export function setupValueEditorBindings(options: SetupValueEditorBindingsOptions) {
  const { props, emit } = options

  const state = createValueEditorState(props)
  const panelProps = createValueEditorPanelProps(props)
  const listeners = createValueEditorListeners(emit)

  return {
    state,
    panelProps,
    listeners,
  }
}
