import type { setupParameterValueInputSwitchBindings } from './setup'

interface CreateParameterValueInputSwitchExposedBindingsOptions {
  setupResult: ReturnType<typeof setupParameterValueInputSwitchBindings>
}

export function createParameterValueInputSwitchExposedBindings(
  options: CreateParameterValueInputSwitchExposedBindingsOptions,
) {
  const { panelProps, listeners } = options.setupResult

  return {
    formatSelectProps: panelProps.formatSelectProps,
    timezoneSelectProps: panelProps.timezoneSelectProps,
    multiValueInputProps: panelProps.multiValueInputProps,
    fallbackInputProps: panelProps.fallbackInputProps,
    valueListeners: listeners.valueListeners,
    multiValueListeners: listeners.multiValueListeners,
    fallbackListeners: listeners.fallbackListeners,
  }
}
