import type { useTreeNodeDrag } from './useTreeNodeDrag'
import type { useTreeNodeMutation } from './useTreeNodeMutation'

interface CreateTreeNodeControllerExposedOptions {
  drag: ReturnType<typeof useTreeNodeDrag>
  mutation: ReturnType<typeof useTreeNodeMutation>
}

export function createTreeNodeControllerExposed(options: CreateTreeNodeControllerExposedOptions) {
  const { drag, mutation } = options

  return {
    isDragOver: drag.isDragOver,
    dragPosition: drag.dragPosition,
    handleDragStart: drag.handleDragStart,
    handleDragEnd: drag.handleDragEnd,
    handleDragOver: drag.handleDragOver,
    handleDragLeave: drag.handleDragLeave,
    handleDrop: drag.handleDrop,
    hasError: mutation.hasError,
    indentSize: mutation.indentSize,
    toggleExpanded: mutation.toggleExpanded,
    updateOperator: mutation.updateOperator,
    updateConditionNegation: mutation.updateConditionNegation,
    updateGroupNegation: mutation.updateGroupNegation,
    copyNode: mutation.copyNode,
    updateBaseField: mutation.updateBaseField,
    updateArrayIndex: mutation.updateArrayIndex,
    getAvailableOperators: mutation.getAvailableOperators,
    switchConditionMode: mutation.switchConditionMode,
    updateComparison: mutation.updateComparison,
    updateValue: mutation.updateValue,
    updateExtraComparison: mutation.updateExtraComparison,
    updateFunction: mutation.updateFunction,
    updateParameter: mutation.updateParameter,
    updateParameterType: mutation.updateParameterType,
    updateParameterValueDataType: mutation.updateParameterValueDataType,
    updateConditionValueDataType: mutation.updateConditionValueDataType,
    updateFunctionValueDataType: mutation.updateFunctionValueDataType,
  }
}
