import type { ParameterTypePayload, ParameterValuePayload, ParameterValueTypePayload } from '../../../../types/nodeEditorPayloads'
import type { FunctionParameterListEmits } from './types'

interface CreateFunctionParameterListListenersOptions {
  emit: FunctionParameterListEmits
}

export function createFunctionParameterListListeners(options: CreateFunctionParameterListListenersOptions) {
  const { emit } = options

  const parameterItemListeners = {
    'update:parameter': (data: ParameterValuePayload) => emit('update:parameter', data),
    'update:parameter-type': (data: ParameterTypePayload) => emit('update:parameter-type', data),
    'update:parameter-value-type': (data: ParameterValueTypePayload) => emit('update:parameter-value-type', data),
  } as const

  return {
    parameterItemListeners,
  }
}
