import type { DragPosition } from '../useTreeNodeController.types'

export function resolveDragPosition(
  nodeType: 'group' | 'condition',
  y: number,
  height: number,
): DragPosition {
  if (nodeType === 'group') {
    if (y < height * 0.25) {
      return 'before'
    }
    if (y > height * 0.75) {
      return 'after'
    }
    return 'inside'
  }

  return y < height * 0.5 ? 'before' : 'after'
}
