import { AVIATOR_FUNCTIONS } from '../../infrastructure/engine/constants'
import { useFunctionRefValueController } from './function-ref-value-controller'
import { createValueInputComputedState } from './useValueInputController.state.computed'
import { createValueInputControllerStateExposed } from './useValueInputController.state.exposed'
import { createValueInputQueries } from './useValueInputController.state.queries'
import { createValueInputStateRefs } from './useValueInputController.state.refs'
import type { UseValueInputControllerOptions } from './useValueInputController.types'

type UseValueInputControllerStateOptions = Pick<
  UseValueInputControllerOptions,
  'props' | 'emitUpdateValueDataType'
>

export function useValueInputControllerState(options: UseValueInputControllerStateOptions) {
  const { props, emitUpdateValueDataType } = options

  const refsState = createValueInputStateRefs()
  const computedState = createValueInputComputedState({
    props,
    emitUpdateValueDataType,
  })

  const functionRefController = useFunctionRefValueController({
    functions: AVIATOR_FUNCTIONS,
  })

  const queries = createValueInputQueries({
    props,
    functions: AVIATOR_FUNCTIONS,
    userSelectedType: refsState.userSelectedType,
    userSelectedValueDataType: computedState.userSelectedValueDataType,
    functionRefController,
  })

  return createValueInputControllerStateExposed({
    refsState,
    computedState,
    functionRefController,
    queries,
  })
}
