import { AVIATOR_FUNCTIONS } from '../../infrastructure/engine/constants'
import type { TreeNode } from '../../infrastructure/engine/types'
import { resolveConditionValueDataType } from '../logic/treeExpressionBuilderLogic'

export function createConditionModeUpdates(
  node: TreeNode,
  availableFields: Array<{ value: string }>,
  getFieldType: (fieldName: string) => string,
): {
    updates: Partial<TreeNode>
    valueDataType: string
  } {
  const defaultField = node.field || (availableFields.length > 0 ? availableFields[0].value : '')
  const fieldType = getFieldType(defaultField)

  return {
    updates: {
      functionName: undefined,
      functionCategory: undefined,
      parameters: undefined,
      field: defaultField,
      comparison: node.comparison || '==',
    },
    valueDataType: resolveConditionValueDataType(fieldType),
  }
}

export function createFunctionModeUpdates(): Partial<TreeNode> {
  const defaultFunc = AVIATOR_FUNCTIONS[0]
  const parameters = defaultFunc.parameters.map((param) => ({
    ...param,
    value: undefined,
  }))

  return {
    field: undefined,
    comparison: undefined,
    value: undefined,
    valueDataType: undefined,
    functionName: defaultFunc.name,
    functionCategory: defaultFunc.category,
    parameters,
  }
}
