import type { NodeValue } from '../../../../infrastructure/engine/types'
import type { FieldModeEditorEmits } from './types'

interface CreateFieldModeEditorListenersOptions {
  emit: FieldModeEditorEmits
  handleFieldChange: (value: string) => void
}

export function createFieldModeEditorListeners(options: CreateFieldModeEditorListenersOptions) {
  const { emit, handleFieldChange } = options

  const controlsListeners = {
    'update:field': (value: string) => handleFieldChange(value),
    'update:array-index': (value: number | undefined) => emit('update:array-index', value),
    'update:comparison': (value: string) => emit('update:comparison', value),
  } as const

  const valueInputListeners = {
    'update:value': (value: NodeValue) => emit('update:value', value),
    'update:value-data-type': (fieldName: string, dataType: string) => {
      emit('update:value-data-type', { fieldName, dataType })
    },
  } as const

  return {
    controlsListeners,
    valueInputListeners,
  }
}
