import { createFunctionParameterListExposedBindings } from './function-parameter-list-bindings/exposed'
import { setupFunctionParameterListBindings } from './function-parameter-list-bindings/setup'
import type {
  UseFunctionParameterListBindingsOptions,
} from './function-parameter-list-bindings/types'

export type {
  FunctionParameterListEmits,
  FunctionParameterListProps,
  UseFunctionParameterListBindingsOptions,
} from './function-parameter-list-bindings/types'

export function useFunctionParameterListBindings(options: UseFunctionParameterListBindingsOptions) {
  const setupResult = setupFunctionParameterListBindings(options)
  return createFunctionParameterListExposedBindings({ setupResult })
}
