import type { setupFieldModeFieldSelectBindings } from './setup'

interface CreateFieldModeFieldSelectExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFieldModeFieldSelectBindings>
}

export function createFieldModeFieldSelectExposedBindings(
  options: CreateFieldModeFieldSelectExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    selectListeners: setupResult.selectListeners,
  }
}
