import type { AviatorFunction, FieldOption } from '../../infrastructure/engine/types'
import {
  VALUE_INPUT_TYPE_OPTIONS,
  getArrayIndexFromReference,
  getBaseFieldNameFromReference,
  getFieldTooltip,
  getValuePlaceholder,
  isCompoundComparison,
  getFieldTypeColor as resolveFieldTypeColor,
  resolveValueInputType,
} from '../logic/value-input'
import type { FunctionRefValueController } from './function-ref-value-controller'
import type { ValueInputProps } from './useValueInputController.types'

interface CreateValueInputQueriesOptions {
  props: ValueInputProps
  functions: readonly AviatorFunction[]
  userSelectedType: { value: string | null }
  userSelectedValueDataType: { value: string }
  functionRefController: FunctionRefValueController
}

export function createValueInputQueries(options: CreateValueInputQueriesOptions) {
  const {
    props,
    functions,
    userSelectedType,
    userSelectedValueDataType,
    functionRefController,
  } = options

  const getPlaceholder = () => getValuePlaceholder(props.fieldType)
  const isCompoundOperator = () => isCompoundComparison(props.comparison)
  const getFieldTypeColor = (type: string) => resolveFieldTypeColor(type)

  const getValueInputType = () => {
    return resolveValueInputType({
      explicitType: userSelectedType.value,
      value: props.value,
      valueIsLiteral: props.valueIsLiteral,
      availableFields: props.availableFields,
      functions,
    })
  }

  const getAvailableValueTypes = () => VALUE_INPUT_TYPE_OPTIONS
  const getValueDataType = () => userSelectedValueDataType.value
  const getBaseFieldName = () => getBaseFieldNameFromReference(props.value)
  const getValueArrayIndex = () => getArrayIndexFromReference(props.value)
  const getFieldTooltipForValue = (field: FieldOption) => getFieldTooltip(field)

  const syncFunctionStateFromValue = () => {
    if (getValueInputType() !== 'function') {
      return
    }
    functionRefController.initializeFromExpression(props.value)
  }

  return {
    getPlaceholder,
    isCompoundOperator,
    getFieldTypeColor,
    getValueInputType,
    getAvailableValueTypes,
    getValueDataType,
    getBaseFieldName,
    getValueArrayIndex,
    getFieldTooltipForValue,
    syncFunctionStateFromValue,
  }
}
