import { useTreeExpressionBuilderActions } from './useTreeExpressionBuilderActions'
import { createTreeExpressionBuilderControllerExposed } from './useTreeExpressionBuilderController.exposed'
import { setupTreeExpressionBuilderWatchers } from './useTreeExpressionBuilderController.watchers'
import { useTreeExpressionBuilderState } from './useTreeExpressionBuilderState'
import type { UseTreeExpressionBuilderControllerOptions } from './useTreeExpressionBuilder.types'

export type {
  ExpressionValidationResult,
  TreeExpressionBuilderProps,
  UiError,
  UseTreeExpressionBuilderControllerOptions,
} from './useTreeExpressionBuilder.types'

export function useTreeExpressionBuilderController(options: UseTreeExpressionBuilderControllerOptions) {
  const state = useTreeExpressionBuilderState(options)
  const actions = useTreeExpressionBuilderActions(state, options.props.notifier)

  setupTreeExpressionBuilderWatchers({
    props: options.props,
    generatedExpression: state.generatedExpression,
    loadExpression: state.loadExpression,
    syncServiceFields: state.syncServiceFields,
    runValidation: state.runValidation,
  })

  return createTreeExpressionBuilderControllerExposed({
    state,
    actions,
  })
}
