import { COMPARISON_OPERATORS } from '../../infrastructure/engine/constants'
import type { ComparisonOperator } from '../../infrastructure/engine/types'
import { resolveConditionValueDataType } from '../logic/treeExpressionBuilderLogic'
import type { UseTreeNodeControllerOptions } from './useTreeNodeController.types'

type UseTreeNodeFieldMutationOptions = Pick<
  UseTreeNodeControllerOptions,
  'props' | 'emitUpdateNode' | 'emitUpdateParameterValueDataType'
>

export function useTreeNodeFieldMutation(options: UseTreeNodeFieldMutationOptions) {
  const { props, emitUpdateNode, emitUpdateParameterValueDataType } = options

  const getFieldType = (fieldName: string): string => {
    const field = props.availableFields.find((item) => item.value === fieldName)
    return field?.type || 'string'
  }

  const getBaseFieldName = (): string => {
    if (!props.node.field) return ''
    const match = props.node.field.match(/^([a-z_][\w.]*)(\[[^\]]+\])?$/i)
    return match ? match[1] : props.node.field
  }

  const updateBaseField = (value: string) => {
    const fieldType = getFieldType(value)
    emitUpdateNode(props.node.id, { field: value, fieldType })

    emitUpdateParameterValueDataType(
      props.node.id,
      'condition_value',
      resolveConditionValueDataType(fieldType === 'array' ? 'string' : fieldType),
    )
  }

  const updateArrayIndex = (index: number | undefined) => {
    const baseFieldName = getBaseFieldName()
    if (!baseFieldName) return

    const newFieldName = index !== undefined ? `${baseFieldName}[${index}]` : baseFieldName
    const fieldType = getFieldType(baseFieldName)
    emitUpdateNode(props.node.id, { field: newFieldName, fieldType })
  }

  const getAvailableOperators = (): ComparisonOperator[] => {
    const baseFieldName = getBaseFieldName()
    const fieldType = getFieldType(baseFieldName || '')

    if (props.node.field && fieldType === 'array' && !/\[\d+\]$/.test(props.node.field)) {
      return COMPARISON_OPERATORS.array
    }

    return COMPARISON_OPERATORS[fieldType as keyof typeof COMPARISON_OPERATORS] || COMPARISON_OPERATORS.string
  }

  return {
    getFieldType,
    updateBaseField,
    updateArrayIndex,
    getAvailableOperators,
  }
}
