import { createFieldRefForwarders } from './forwarders'
import { createFieldRefResolvers } from './resolvers'
import { createFieldRefState } from './state'
import type { FieldRefEditorProps } from './types'

interface SetupFieldRefEditorBindingsOptions {
  props: FieldRefEditorProps
  emitUpdateField: (value: string) => void
}

export function setupFieldRefEditorBindings(options: SetupFieldRefEditorBindingsOptions) {
  const { props, emitUpdateField } = options

  const state = createFieldRefState(props)
  const resolvers = createFieldRefResolvers(props)
  const forwarders = createFieldRefForwarders({ emitUpdateField })

  return {
    state,
    resolvers,
    forwarders,
  }
}
