import type { setupConditionNodeViewBindings } from './setup'

interface CreateConditionNodeViewExposedBindingsOptions {
  setupResult: ReturnType<typeof setupConditionNodeViewBindings>
}

export function createConditionNodeViewExposedBindings(
  options: CreateConditionNodeViewExposedBindingsOptions,
) {
  const { conditionNodeMode, listeners } = options.setupResult

  return {
    conditionNodeMode,
    modeSwitchListeners: listeners.modeSwitchListeners,
    fieldModeListeners: listeners.fieldModeListeners,
    functionModeListeners: listeners.functionModeListeners,
  }
}
