import { useValueInputControllerActions } from './useValueInputController.actions'
import { createValueInputControllerExposedState } from './useValueInputController.exposed'
import { useValueInputControllerState } from './useValueInputController.state'
import type { UseValueInputControllerOptions } from './useValueInputController.types'
import { registerValueInputControllerWatchers } from './useValueInputController.watchers'

export type {
  UseValueInputControllerOptions,
  ValueInputProps,
} from './useValueInputController.types'

export function useValueInputController(options: UseValueInputControllerOptions) {
  const state = useValueInputControllerState({
    props: options.props,
    emitUpdateValueDataType: options.emitUpdateValueDataType,
  })

  const actions = useValueInputControllerActions(state, {
    props: options.props,
    emitUpdateValue: options.emitUpdateValue,
    emitUpdateType: options.emitUpdateType,
  })

  registerValueInputControllerWatchers({
    props: options.props,
    state,
  })

  return createValueInputControllerExposedState(state, actions)
}
