import type { setupFieldModeControlsBindings } from './setup'

interface CreateFieldModeControlsExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFieldModeControlsBindings>
}

export function createFieldModeControlsExposedBindings(
  options: CreateFieldModeControlsExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    fieldSelectListeners: setupResult.listeners.fieldSelectListeners,
    arrayIndexListeners: setupResult.listeners.arrayIndexListeners,
    comparisonSelectListeners: setupResult.listeners.comparisonSelectListeners,
  }
}
