import type { UseFieldModeFieldSelectBindingsOptions } from './types'

export function setupFieldModeFieldSelectBindings(options: UseFieldModeFieldSelectBindingsOptions) {
  const { emit } = options

  const selectListeners = {
    'update:model-value': (value: string) => emit('update:field', value),
  } as const

  return {
    selectListeners,
  }
}
