import { AVIATOR_FUNCTIONS } from '../../infrastructure/engine/constants'
import type { FunctionCategory } from './useFunctionModeEditorController.types'
import { FUNCTION_CATEGORY_BLUEPRINT } from './useFunctionModeEditorController.state.constants'

export function buildFunctionCategories(): FunctionCategory[] {
  const categories: FunctionCategory[] = FUNCTION_CATEGORY_BLUEPRINT.map((item) => ({
    name: item.name,
    label: item.label,
    functions: [],
  }))

  AVIATOR_FUNCTIONS.forEach((func) => {
    const category = categories.find((item) => item.name === func.category)
    if (category) {
      category.functions.push(func)
    }
  })

  return categories.filter((item) => item.functions.length > 0)
}
