import { createConditionValueEditorForwarders } from './forwarders'
import { createConditionValueEditorListeners } from './listeners'
import { createConditionValueEditorPanelProps } from './panelProps'
import { createConditionValueEditorState } from './state'
import type { ConditionValueEditorEmits, ConditionValueEditorProps } from './types'

interface SetupConditionValueEditorBindingsOptions {
  props: ConditionValueEditorProps
  emit: ConditionValueEditorEmits
}

export function setupConditionValueEditorBindings(options: SetupConditionValueEditorBindingsOptions) {
  const { props, emit } = options

  const state = createConditionValueEditorState(props)
  const forwarders = createConditionValueEditorForwarders(emit)
  const listeners = createConditionValueEditorListeners({ forwarders })
  const panelProps = createConditionValueEditorPanelProps(props, state)

  return {
    state,
    listeners,
    panelProps,
  }
}
