import type { setupTreeExpressionBuilderBindings } from './setup'

interface CreateTreeExpressionBuilderExposedBindingsOptions {
  setupResult: ReturnType<typeof setupTreeExpressionBuilderBindings>
}

export function createTreeExpressionBuilderExposedBindings(
  options: CreateTreeExpressionBuilderExposedBindingsOptions,
) {
  const { controller, listeners, hasDataPreview } = options.setupResult

  return {
    extractedFields: controller.extractedFields,
    dataSourceInfo: controller.dataSourceInfo,
    rootNodes: controller.rootNodes,
    availableFields: controller.availableFields,
    validationErrors: controller.validationErrors,
    allErrors: controller.allErrors,
    generatedExpression: controller.generatedExpression,
    validating: controller.validating,
    validationResult: controller.validationResult,
    addGroup: controller.addGroup,
    expandAll: controller.expandAll,
    collapseAll: controller.collapseAll,
    updateNode: controller.updateNode,
    addChildNode: controller.addChildNode,
    removeNode: controller.removeNode,
    moveNodeUpAction: controller.moveNodeUpAction,
    moveNodeDownAction: controller.moveNodeDownAction,
    copyNodeAction: controller.copyNodeAction,
    handleParameterTypeUpdate: controller.handleParameterTypeUpdate,
    handleParameterValueDataTypeUpdate: controller.handleParameterValueDataTypeUpdate,
    handleDragNode: controller.handleDragNode,
    clearExpression: controller.clearExpression,
    validateExpressionManually: controller.validateExpressionManually,
    copyExpression: controller.copyExpression,
    formatExpression: controller.formatExpression,
    getParameterDataType: controller.getParameterDataType,
    hasDataPreview,
    toolbarListeners: listeners.toolbarListeners,
    treeCanvasListeners: listeners.treeCanvasListeners,
    expressionPreviewListeners: listeners.expressionPreviewListeners,
  }
}
