import { computed } from 'vue'
import type { FunctionRefEditorProps } from './types'

export function createFunctionRefEditorState(props: FunctionRefEditorProps) {
  const hasSelectedFunction = computed(() => Boolean(props.selectedFunction))
  const showParameters = computed(() => hasSelectedFunction.value && props.functionParameters.length > 0)

  return {
    hasSelectedFunction,
    showParameters,
  }
}
