import { createFunctionParameterListListeners } from './listeners'
import type { UseFunctionParameterListBindingsOptions } from './types'

export function setupFunctionParameterListBindings(options: UseFunctionParameterListBindingsOptions) {
  const { props, emit } = options

  const getCurrentDataType = (paramName: string): string | undefined => {
    if (!props.getParameterDataType) return undefined
    return props.getParameterDataType(props.node.id, paramName)
  }

  const listeners = createFunctionParameterListListeners({ emit })

  return {
    getCurrentDataType,
    listeners,
  }
}
