import { createTreeExpressionBuilderReorderActions } from './useTreeExpressionBuilderNodeActions.reorder'
import { createTreeExpressionBuilderNodeActionsExposed } from './useTreeExpressionBuilderNodeActions.exposed'
import type { TreeExpressionBuilderNotifier } from './treeExpressionBuilderNotifier'
import { type TreeExpressionBuilderState, createNodeActionHelpers } from './useTreeExpressionBuilderNodeActions.shared'
import { createTreeExpressionBuilderStructureActions } from './useTreeExpressionBuilderNodeActions.structure'

export function useTreeExpressionBuilderNodeActions(
  state: TreeExpressionBuilderState,
  notifier: TreeExpressionBuilderNotifier,
) {
  const helpers = createNodeActionHelpers(state, notifier)

  const structureActions = createTreeExpressionBuilderStructureActions({
    state,
    commitNodeMutation: helpers.commitNodeMutation,
  })

  const reorderActions = createTreeExpressionBuilderReorderActions({
    state,
    commitNodeMutation: helpers.commitNodeMutation,
    notifyDragFailure: helpers.notifyDragFailure,
    notifier,
  })

  return createTreeExpressionBuilderNodeActionsExposed({
    structureActions,
    reorderActions,
  })
}
