import type { setupConditionValueInputSwitchBindings } from './setup'

interface CreateConditionValueInputSwitchExposedBindingsOptions {
  setupResult: ReturnType<typeof setupConditionValueInputSwitchBindings>
}

export function createConditionValueInputSwitchExposedBindings(
  options: CreateConditionValueInputSwitchExposedBindingsOptions,
) {
  const { panelProps, listeners } = options.setupResult

  return {
    booleanSelectProps: panelProps.booleanSelectProps,
    nullSelectProps: panelProps.nullSelectProps,
    multiValueInputProps: panelProps.multiValueInputProps,
    urlInputProps: panelProps.urlInputProps,
    dateTimeInputProps: panelProps.dateTimeInputProps,
    fallbackInputProps: panelProps.fallbackInputProps,
    valueListeners: listeners.valueListeners,
    multiValueListeners: listeners.multiValueListeners,
    dateValueListeners: listeners.dateValueListeners,
    urlListeners: listeners.urlListeners,
    fallbackListeners: listeners.fallbackListeners,
  }
}
