import type { TreeNodeViewEmits, TreeNodeViewProps } from './types'
import { createUseTreeNodeViewBindingsExposed } from './useTreeNodeViewBindings.exposed'
import { setupTreeNodeViewBindings } from './view-bindings/setup'

export interface UseTreeNodeViewBindingsOptions {
  props: TreeNodeViewProps
  emit: TreeNodeViewEmits
}

export function useTreeNodeViewBindings(options: UseTreeNodeViewBindingsOptions) {
  const setupResult = setupTreeNodeViewBindings(options)
  return createUseTreeNodeViewBindingsExposed({ setupResult })
}
