import { createFunctionSelectPanelExposedBindings } from './function-select-panel-bindings/exposed'
import { setupFunctionSelectPanelBindings } from './function-select-panel-bindings/setup'
import type {
  UseFunctionSelectPanelBindingsOptions,
} from './function-select-panel-bindings/types'

export type {
  FunctionSelectPanelEmits,
  FunctionSelectPanelProps,
  UseFunctionSelectPanelBindingsOptions,
} from './function-select-panel-bindings/types'

export function useFunctionSelectPanelBindings(options: UseFunctionSelectPanelBindingsOptions) {
  const setupResult = setupFunctionSelectPanelBindings(options)
  return createFunctionSelectPanelExposedBindings({ setupResult })
}
