import type { TreeNodeChildrenForwarders } from './types'

interface CreateTreeNodeChildrenListenersOptions {
  bindings: TreeNodeChildrenForwarders
}

export function createTreeNodeChildrenListeners(options: CreateTreeNodeChildrenListenersOptions) {
  const { bindings } = options

  const childNodeListeners = {
    'update-node': bindings.onUpdateNode,
    'add-child': bindings.onAddChild,
    'remove-node': bindings.onRemoveNode,
    'move-up': bindings.onMoveUp,
    'move-down': bindings.onMoveDown,
    'copy-node': bindings.onCopyNode,
    'update-parameter-type': bindings.onUpdateParameterType,
    'update-parameter-value-data-type': bindings.onUpdateParameterValueDataType,
    'drag-node': bindings.onDragNode,
  }

  return {
    childNodeListeners,
  }
}
