<template>
  <ValueInput
    :key="`${node.id}-value`"
    :value="node.value"
    :field-type="selectedFunction.returnType"
    :field-name="selectedFunction.name"
    :comparison="node.comparison"
    :available-fields="availableFields"
    :current-data-type="currentDataType"
    v-on="valueInputListeners"
  />
</template>

<script setup lang="ts">
import type { AviatorFunction, FieldOption, TreeNode } from '../../../../../infrastructure/engine/types'
import ValueInput from '../../../inputs/ValueInput.vue'
import {
  type FunctionComparisonValueInputEmits,
  useFunctionComparisonValueInputBindings,
} from './useFunctionComparisonValueInputBindings'

defineProps<{
  node: TreeNode
  selectedFunction: AviatorFunction
  availableFields: FieldOption[]
  currentDataType: string
}>()

const emit = defineEmits<FunctionComparisonValueInputEmits>()

const { valueInputListeners } = useFunctionComparisonValueInputBindings({
  emit,
})
</script>
