import type { useTreeExpressionBuilderState } from './useTreeExpressionBuilderState'
import type { TreeExpressionBuilderNotifier } from './treeExpressionBuilderNotifier'

export type TreeExpressionBuilderState = ReturnType<typeof useTreeExpressionBuilderState>

interface CommitNodeMutationOptions {
  validate?: boolean
}

export function createNodeActionHelpers(
  state: TreeExpressionBuilderState,
  notifier: TreeExpressionBuilderNotifier,
) {
  const commitNodeMutation = (options?: CommitNodeMutationOptions) => {
    state.parseError.value = null
    state.regenerateExpression()
    if (options?.validate) {
      state.runValidation()
    }
  }

  const notifyDragFailure = (reason?: string) => {
    if (reason === 'descendant_target') {
      notifier.warning('不能将节点拖拽到自己的子节点中')
      return
    }

    if (reason === 'invalid_target') {
      notifier.warning('只能拖拽到分组内部')
    }
  }

  return {
    commitNodeMutation,
    notifyDragFailure,
  }
}
