import { computed } from 'vue'
import type { FunctionRefParameterInputProps } from './item.types'

export function createFunctionRefParameterItemPanelProps(props: FunctionRefParameterInputProps) {
  const labelProps = computed(() => ({
    description: props.param.description || props.param.name,
    required: props.param.required,
  }))

  const inputBodyProps = computed(() => ({
    param: props.param,
    availableFields: props.availableFields,
  }))

  return {
    labelProps,
    inputBodyProps,
  }
}
