import type { useFieldModeEditorControllerActions } from './useFieldModeEditorController.actions'
import type { useFieldModeEditorControllerState } from './useFieldModeEditorController.state'

interface CreateFieldModeEditorControllerExposedOptions {
  state: ReturnType<typeof useFieldModeEditorControllerState>
  actions: ReturnType<typeof useFieldModeEditorControllerActions>
}

export function createFieldModeEditorControllerExposed(
  options: CreateFieldModeEditorControllerExposedOptions,
) {
  const { state, actions } = options

  return {
    baseFieldName: state.baseFieldName,
    arrayIndex: state.arrayIndex,
    isArrayField: state.isArrayField,
    fieldType: state.fieldType,
    needsValue: state.needsValue,
    getFieldTooltip: state.getFieldTooltip,
    getTypeColor: state.getTypeColor,
    handleFieldChange: actions.handleFieldChange,
  }
}
