import { computed } from 'vue'
import type { ValueInputSwitchPanelProps } from '../types'

export function createFieldRefEditorProps(props: ValueInputSwitchPanelProps) {
  return computed(() => ({
    value: String(props.value || ''),
    availableFields: props.availableFields || [],
    showArrayIndex: true,
    arrayIndex: props.valueArrayIndex,
    showArrayHint: true,
    getFieldTooltip: props.getFieldTooltip,
    getTypeColor: props.getFieldTypeColor,
  }))
}
