import { createAviatorExpressionBuilderLegacyModalExposedBindings } from './legacy-modal-bindings/exposed'
import { setupAviatorExpressionBuilderLegacyModalBindings } from './legacy-modal-bindings/setup'
import type {
  CreateLegacyModalBindingsOptions,
} from './legacy-modal-bindings/types'

export type {
  AviatorExpressionBuilderLegacyModalEmits,
  AviatorExpressionBuilderLegacyModalProps,
  AviatorExpressionBuilderLegacyModalExposed,
  LegacyModalFieldOption,
} from './legacy-modal-bindings/types'

export function useAviatorExpressionBuilderLegacyModalBindings(
  options: CreateLegacyModalBindingsOptions,
) {
  const setupResult = setupAviatorExpressionBuilderLegacyModalBindings(options)
  return createAviatorExpressionBuilderLegacyModalExposedBindings({ setupResult })
}
