import { computed } from 'vue'
import type { ConditionValueEditorProps } from '../condition-value-bindings/types'
import type { ParameterValueEditorProps } from '../parameter-value-bindings/types'
import type { ValueEditorProps } from './types'

export function createValueEditorPanelProps(props: ValueEditorProps) {
  const conditionEditorProps = computed<ConditionValueEditorProps>(() => ({
    value: props.value,
    fieldType: props.fieldType,
    comparison: props.comparison,
    valueDataType: props.valueDataType,
    placeholder: props.placeholder,
    multiValues: props.multiValues,
    dateValue: props.dateValue,
    urlError: props.urlError,
    showDataTypeSwitch: props.showDataTypeSwitch,
  }))

  const parameterEditorProps = computed<ParameterValueEditorProps>(() => ({
    value: props.value,
    displayValue: props.displayValue,
    valueDataType: props.valueDataType,
    multiValues: props.multiValues,
    parameterName: props.parameterName,
    parameterDescription: props.parameterDescription,
    parameterType: props.parameterType,
    showDataTypeSwitch: props.showDataTypeSwitch,
  }))

  return {
    conditionEditorProps,
    parameterEditorProps,
  }
}
