import type { NodeValue } from '../../../../../../infrastructure/engine/types'
import type { UseFunctionComparisonValueInputBindingsOptions } from './types'

export function createFunctionComparisonValueInputListeners(
  options: UseFunctionComparisonValueInputBindingsOptions,
) {
  const { emit } = options

  const valueInputListeners = {
    'update:value': (value: NodeValue) => emit('update:value', value),
    'update:value-data-type': (fieldName: string, dataType: string) => {
      emit('update:value-data-type', { fieldName, dataType })
    },
  } as const

  return {
    valueInputListeners,
  }
}
