import type { createConditionValueEditorForwarders } from './forwarders'

interface CreateConditionValueEditorListenersOptions {
  forwarders: ReturnType<typeof createConditionValueEditorForwarders>
}

export function createConditionValueEditorListeners(options: CreateConditionValueEditorListenersOptions) {
  const { forwarders } = options

  const valueInputSwitchListeners = {
    'update:value': forwarders.onUpdateValue,
    'update:multi-values': forwarders.onUpdateMultiValues,
    'update:date-value': forwarders.onUpdateDateValue,
    'blur:url': forwarders.onBlurUrl,
  } as const

  const dataTypeSwitchListeners = {
    'update:model-value': forwarders.onUpdateValueDataType,
  } as const

  return {
    valueInputSwitchListeners,
    dataTypeSwitchListeners,
  }
}
