import { unref } from 'vue'
import type { ValueInputSwitchPanelProps } from '../switch-panel/types'
import type { CreateValueInputSwitchPanelFunctionPropsOptions } from './panel-props.function.types'

type ValueInputSwitchPanelFunctionProps = Pick<
  ValueInputSwitchPanelProps,
  | 'selectedFunctionName'
  | 'functionCategories'
  | 'selectedFunction'
  | 'functionParameters'
  | 'functionExpression'
>

export function createValueInputSwitchPanelFunctionProps(
  options: CreateValueInputSwitchPanelFunctionPropsOptions,
): ValueInputSwitchPanelFunctionProps {
  const { controller, state } = options

  return {
    selectedFunctionName: unref(controller.selectedFunctionName),
    functionCategories: unref(controller.functionCategories),
    selectedFunction: unref(controller.selectedFunction),
    functionParameters: unref(controller.functionParameters),
    functionExpression: state.functionExpression.value,
  }
}
