import type {
  NodeActionCommonButtonsListeners,
  NodeActionGroupAddListeners,
  UseNodeActionsBindingsOptions,
} from './types'

export function createNodeActionsListeners(options: UseNodeActionsBindingsOptions) {
  const { emit } = options

  const groupAddListeners: NodeActionGroupAddListeners = {
    'add-child': (parentId, nodeType) => {
      if (nodeType === 'function') return
      emit('add-child', parentId, nodeType)
    },
  }

  const commonButtonListeners: NodeActionCommonButtonsListeners = {
    'move-up': (nodeId: string) => emit('move-up', nodeId),
    'move-down': (nodeId: string) => emit('move-down', nodeId),
    'copy-node': (nodeId: string) => emit('copy-node', nodeId),
    'remove-node': (nodeId: string) => emit('remove-node', nodeId),
  }

  return {
    groupAddListeners,
    commonButtonListeners,
  }
}
