import type { TreeNode } from '../../types'
import {
  detachSourceNode,
  insertSourceNodeInsideTarget,
  insertSourceNodeRelativeToTarget,
  restoreSourceNode,
} from './drag-structure'
import { findNode, isDescendant, updateNodeHierarchy } from './find'
import type { DragNodePosition, OperationResult } from './types'

export function dragNode(
  nodes: TreeNode[],
  sourceNodeId: string,
  targetNodeId: string,
  position: DragNodePosition,
): OperationResult {
  const sourceResult = findNode(nodes, sourceNodeId)
  const targetResult = findNode(nodes, targetNodeId)

  const sourceNode = sourceResult.node
  const targetNode = targetResult.node

  if (!sourceNode || !targetNode) {
    console.error('无法找到源节点或目标节点')
    return { success: false, reason: 'node_not_found' }
  }

  if (isDescendant(nodes, sourceNodeId, targetNodeId)) {
    return { success: false, reason: 'descendant_target' }
  }

  detachSourceNode({
    nodes,
    sourceNodeId,
    sourceResult,
  })

  let newParentId: string | undefined
  let newLevel: number

  if (position === 'inside') {
    if (targetNode.type !== 'group') {
      restoreSourceNode({
        nodes,
        sourceNode,
        sourceResult,
      })
      return { success: false, reason: 'invalid_target' }
    }

    newParentId = targetNode.id
    newLevel = targetNode.level + 1

    insertSourceNodeInsideTarget({
      sourceNode,
      targetNode,
    })
  } else {
    newParentId = targetResult.parent?.id
    newLevel = targetNode.level

    insertSourceNodeRelativeToTarget({
      nodes,
      sourceNode,
      targetNodeId,
      targetResult,
      position,
    })
  }

  updateNodeHierarchy(sourceNode, newParentId, newLevel)
  return { success: true }
}
