import { createParameterValueInputSwitchListeners } from './listeners'
import { createParameterValueInputSwitchPanelProps } from './panelProps'
import type { ParameterValueInputSwitchEmits, ParameterValueInputSwitchProps } from './types'

interface SetupParameterValueInputSwitchBindingsOptions {
  props: ParameterValueInputSwitchProps
  emit: ParameterValueInputSwitchEmits
}

export function setupParameterValueInputSwitchBindings(
  options: SetupParameterValueInputSwitchBindingsOptions,
) {
  const { props, emit } = options

  const panelProps = createParameterValueInputSwitchPanelProps(props)
  const listeners = createParameterValueInputSwitchListeners(emit)

  return {
    panelProps,
    listeners,
  }
}
