import { ref } from 'vue'
import type { Ref } from 'vue'

export interface ParameterInputControllerStateRefs {
  savedStringValue: Ref<string>
  userSelectedType: Ref<string | null>
  userHasSelectedDataType: Ref<boolean>
  userSelectedValueDataType: Ref<string | null>
}

export function createParameterInputControllerStateRefs(): ParameterInputControllerStateRefs {
  return {
    savedStringValue: ref<string>(''),
    userSelectedType: ref<string | null>(null),
    userHasSelectedDataType: ref<boolean>(false),
    userSelectedValueDataType: ref<string | null>(null),
  }
}
