import { computed } from 'vue'
import type { ValueInputSwitchPanelProps } from '../types'

export function createValueInputPanelBodyState(props: ValueInputSwitchPanelProps) {
  const isValueMode = computed(() => props.currentInputType === 'value')
  const isFieldMode = computed(() => props.currentInputType === 'field')
  const isFunctionMode = computed(() => props.currentInputType === 'function')

  return {
    isValueMode,
    isFieldMode,
    isFunctionMode,
  }
}
