import { createValueInputForwarders } from '../value-input-forwarders'
import { createValueInputPanelBodyListeners } from './listeners'
import { createValueInputPanelBodyPanelProps } from './panelProps'
import { createValueInputPanelBodyState } from './state'
import type { UseValueInputPanelBodyBindingsOptions } from './types'

export function setupValueInputPanelBodyBindings(options: UseValueInputPanelBodyBindingsOptions) {
  const state = createValueInputPanelBodyState(options.props)
  const forwarders = createValueInputForwarders(options.emit)
  const listeners = createValueInputPanelBodyListeners(forwarders)
  const panelProps = createValueInputPanelBodyPanelProps(options.props)

  return {
    state,
    listeners,
    panelProps,
  }
}
