import type { TreeNodeViewEmits, TreeNodeViewProps } from '../types'
import { createTreeNodeViewForwarders } from '../useTreeNodeViewBindings.forwarders'
import { createTreeNodeViewHandlers } from '../useTreeNodeViewBindings.handlers'
import { createTreeNodeControllerBindings } from './controller'
import { createTreeNodeViewExposedBindings } from './exposed'
import { createTreeNodeViewListeners } from './listeners'
import { createTreeNodeClasses } from './nodeClasses'

export interface SetupTreeNodeViewBindingsOptions {
  props: TreeNodeViewProps
  emit: TreeNodeViewEmits
}

export function setupTreeNodeViewBindings(options: SetupTreeNodeViewBindingsOptions) {
  const { props, emit } = options

  const controller = createTreeNodeControllerBindings(props, emit)

  const handlers = createTreeNodeViewHandlers({
    updateConditionValueDataType: controller.updateConditionValueDataType,
    updateFunctionValueDataType: controller.updateFunctionValueDataType,
    updateParameter: controller.updateParameter,
    updateParameterType: controller.updateParameterType,
    updateParameterValueDataType: controller.updateParameterValueDataType,
  })

  const forwarders = createTreeNodeViewForwarders(emit)

  const nodeClasses = createTreeNodeClasses({
    props,
    isDragOver: controller.isDragOver,
    dragPosition: controller.dragPosition,
    hasError: controller.hasError,
  })

  const listeners = createTreeNodeViewListeners({
    controller,
    handlers,
    forwarders,
  })

  const exposedBindings = createTreeNodeViewExposedBindings({
    controller,
    handlers,
    forwarders,
    nodeClasses,
  })

  return {
    exposedBindings,
    listeners,
  }
}
