import { computed } from 'vue'
import { useFunctionModeEditorController } from '../../../composables/useFunctionModeEditorController'
import { createFunctionModeEditorListeners } from './listeners'
import type { UseFunctionModeEditorBindingsOptions } from './types'

export function setupFunctionModeEditorBindings(options: UseFunctionModeEditorBindingsOptions) {
  const { props, emit } = options

  const controller = useFunctionModeEditorController({ props })

  const listeners = createFunctionModeEditorListeners({
    emit,
    showFunctionUsage: controller.showFunctionUsage,
  })

  const shouldRenderComparison = computed(() => (
    Boolean(controller.selectedFunction.value)
    && props.node.comparison !== undefined
    && controller.shouldShowComparison.value
  ))

  const comparisonSelectedFunction = computed(() => controller.selectedFunction.value!)

  return {
    controller,
    listeners,
    shouldRenderComparison,
    comparisonSelectedFunction,
  }
}
