import type { ValueInputPanelBodyForwarders } from '../switch-panel/panel-body-listeners.shared'
import { createValueInputSwitchPanelBodyListeners } from './listeners.panel-body'
import { createValueInputSwitchPanelTypeSelectorListeners } from './listeners.type'

interface ValueInputSwitchPanelForwarders extends ValueInputPanelBodyForwarders {
  onUpdateType: (type: string) => void
}

export function createValueInputSwitchPanelListeners(forwarders: ValueInputSwitchPanelForwarders) {
  const typeSelectorListeners = createValueInputSwitchPanelTypeSelectorListeners(forwarders)
  const panelBodyListeners = createValueInputSwitchPanelBodyListeners(forwarders)

  return {
    typeSelectorListeners,
    panelBodyListeners,
  }
}
