import {
  DEFAULT_PARAMETER_TYPE_OPTIONS,
  LAMBDA_PARAMETER_TYPE_OPTIONS,
  type ParameterInputType,
} from './constants'

export function buildAvailableParameterTypes(
  isLambdaParameter: boolean,
): Array<{ value: ParameterInputType, label: string }> {
  return isLambdaParameter ? LAMBDA_PARAMETER_TYPE_OPTIONS : DEFAULT_PARAMETER_TYPE_OPTIONS
}
