import { computed } from 'vue'
import {
  resolveValueDataType,
  resolveValueDataTypeFieldName,
  toDateValue,
  toMultiValues,
} from '../logic/value-input'
import type { ValueInputProps } from './useValueInputController.types'

interface CreateValueInputComputedStateOptions {
  props: ValueInputProps
  emitUpdateValueDataType: (fieldName: string, dataType: string) => void
}

export function createValueInputComputedState(options: CreateValueInputComputedStateOptions) {
  const { props, emitUpdateValueDataType } = options

  const userSelectedValueDataType = computed({
    get: () => resolveValueDataType(props.currentDataType),
    set: (value: string) => {
      emitUpdateValueDataType(resolveValueDataTypeFieldName(props.fieldName), value)
    },
  })

  const dateValue = computed(() => toDateValue(props.value))
  const multiValues = computed(() => toMultiValues(props.value))

  return {
    userSelectedValueDataType,
    dateValue,
    multiValues,
  }
}
