export function setDragTargetOpacity(event: DragEvent, opacity: string): void {
  const target = event.currentTarget as HTMLElement | null
  if (target) {
    target.style.opacity = opacity
  }
}

export function getCurrentTargetRect(event: DragEvent): DOMRect | null {
  const currentTarget = event.currentTarget as HTMLElement | null
  return currentTarget?.getBoundingClientRect() ?? null
}
