import type { createTreeExpressionBuilderReorderActions } from './useTreeExpressionBuilderNodeActions.reorder'
import type { createTreeExpressionBuilderStructureActions } from './useTreeExpressionBuilderNodeActions.structure'

interface CreateTreeExpressionBuilderNodeActionsExposedOptions {
  structureActions: ReturnType<typeof createTreeExpressionBuilderStructureActions>
  reorderActions: ReturnType<typeof createTreeExpressionBuilderReorderActions>
}

export function createTreeExpressionBuilderNodeActionsExposed(
  options: CreateTreeExpressionBuilderNodeActionsExposedOptions,
) {
  const { structureActions, reorderActions } = options

  return {
    addGroup: structureActions.addGroup,
    expandAll: structureActions.expandAll,
    collapseAll: structureActions.collapseAll,
    updateNode: structureActions.updateNode,
    addChildNode: structureActions.addChildNode,
    removeNode: structureActions.removeNode,
    handleParameterTypeUpdate: structureActions.handleParameterTypeUpdate,
    handleParameterValueDataTypeUpdate: structureActions.handleParameterValueDataTypeUpdate,
    getParameterDataType: structureActions.getParameterDataType,
    moveNodeUpAction: reorderActions.moveNodeUpAction,
    moveNodeDownAction: reorderActions.moveNodeDownAction,
    copyNodeAction: reorderActions.copyNodeAction,
    handleDragNode: reorderActions.handleDragNode,
  }
}
