import { computed } from 'vue'
import type { ValueInputSwitchPanelProps } from '../types'

export function createFunctionRefEditorProps(props: ValueInputSwitchPanelProps) {
  return computed(() => ({
    selectedFunctionName: props.selectedFunctionName,
    functionCategories: props.functionCategories,
    selectedFunction: props.selectedFunction,
    functionParameters: props.functionParameters,
    availableFields: props.availableFields || [],
    functionExpression: props.functionExpression,
  }))
}
