import { watch } from 'vue'
import type { useParameterInputControllerActions } from './useParameterInputController.actions'
import type { useParameterInputControllerState } from './useParameterInputController.state'
import type { ParameterInputProps } from './useParameterInputController.types'

type ParameterInputControllerState = ReturnType<typeof useParameterInputControllerState>
type ParameterInputControllerActions = ReturnType<typeof useParameterInputControllerActions>

interface RegisterParameterInputControllerWatchersOptions {
  props: ParameterInputProps
  state: ParameterInputControllerState
  actions: ParameterInputControllerActions
}

export function registerParameterInputControllerWatchers(options: RegisterParameterInputControllerWatchersOptions) {
  const { props, state, actions } = options

  watch(
    () => props.value,
    (newValue, oldValue) => {
      if (oldValue !== null && oldValue !== undefined && oldValue !== newValue) {
        if (typeof oldValue === 'string' || typeof oldValue === 'number' || typeof oldValue === 'boolean') {
          const isFieldReference = typeof oldValue === 'string'
            && props.availableFields.some((field) => field.value === oldValue)
          const isLambdaExpression = typeof oldValue === 'string' && oldValue.includes('lambda(')

          if (!isFieldReference && !isLambdaExpression) {
            state.savedStringValue.value = String(oldValue)
          }
        }
      }

      if (newValue !== null && newValue !== undefined) {
        if (
          (typeof newValue === 'string' || typeof newValue === 'number' || typeof newValue === 'boolean')
          && state.savedStringValue.value === ''
        ) {
          state.savedStringValue.value = String(newValue)
        }
      }

      if (!newValue || newValue === '' || newValue === null || newValue === undefined) {
        actions.initializeLambdaParameter()
      }
    },
    { deep: true, immediate: true },
  )

  watch(
    () => props.functionName,
    () => {
      actions.initializeLambdaParameter()
    },
    { immediate: true },
  )

  watch(
    () => [props.parameter.name, props.parameter.description],
    () => {
      actions.initializeLambdaParameter()
    },
    { immediate: true },
  )
}
