import type { setupFunctionComparisonPanelBindings } from './setup'

interface CreateFunctionComparisonPanelExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionComparisonPanelBindings>
}

export function createFunctionComparisonPanelExposedBindings(
  options: CreateFunctionComparisonPanelExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    currentDataType: setupResult.currentDataType,
    comparisonOperatorListeners: setupResult.listeners.comparisonOperatorListeners,
    comparisonValueInputListeners: setupResult.listeners.comparisonValueInputListeners,
  }
}
