import { createParameterModeConditionExposedBindings } from './parameter-mode-condition-bindings/exposed'
import { setupParameterModeConditionBindings } from './parameter-mode-condition-bindings/setup'
import type {
  UseParameterModeConditionBindingsOptions,
} from './parameter-mode-condition-bindings/types'

export type {
  ParameterModeConditionEmits,
  ParameterModeConditionProps,
  UseParameterModeConditionBindingsOptions,
} from './parameter-mode-condition-bindings/types'

export function useParameterModeConditionBindings(options: UseParameterModeConditionBindingsOptions) {
  const setupResult = setupParameterModeConditionBindings(options)
  return createParameterModeConditionExposedBindings({ setupResult })
}
