import type { setupFunctionParameterListBindings } from './setup'

interface CreateFunctionParameterListExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionParameterListBindings>
}

export function createFunctionParameterListExposedBindings(
  options: CreateFunctionParameterListExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    getCurrentDataType: setupResult.getCurrentDataType,
    parameterItemListeners: setupResult.listeners.parameterItemListeners,
  }
}
