import { createTreeCanvasGroupForwarders } from './group-forwarders'
import { createTreeCanvasListeners } from './listeners'
import { createTreeCanvasNodeForwarders } from './node-forwarders'
import type { UseTreeCanvasBindingsOptions } from './types'

export function setupTreeCanvasBindings(options: UseTreeCanvasBindingsOptions) {
  const nodeForwarders = createTreeCanvasNodeForwarders(options.emit)
  const groupForwarders = createTreeCanvasGroupForwarders(options.emit)
  const listeners = createTreeCanvasListeners({
    nodeForwarders,
    groupForwarders,
  })

  return {
    listeners,
  }
}
