import { createTreeExpressionBuilderActionsExposed } from './useTreeExpressionBuilderActions.exposed'
import { useTreeExpressionBuilderExpressionActions } from './useTreeExpressionBuilderExpressionActions'
import { useTreeExpressionBuilderNodeActions } from './useTreeExpressionBuilderNodeActions'
import type { useTreeExpressionBuilderState } from './useTreeExpressionBuilderState'
import {
  type TreeExpressionBuilderNotifier,
  defaultTreeExpressionBuilderNotifier,
} from './treeExpressionBuilderNotifier'

type TreeExpressionBuilderState = ReturnType<typeof useTreeExpressionBuilderState>

export function useTreeExpressionBuilderActions(
  state: TreeExpressionBuilderState,
  notifier?: TreeExpressionBuilderNotifier,
) {
  const injectedNotifier = notifier || defaultTreeExpressionBuilderNotifier
  const nodeActions = useTreeExpressionBuilderNodeActions(state, injectedNotifier)
  const expressionActions = useTreeExpressionBuilderExpressionActions(state, injectedNotifier)

  return createTreeExpressionBuilderActionsExposed({
    nodeActions,
    expressionActions,
  })
}
