import type { AviatorFunction, NodeValue } from '../../../infrastructure/engine/types'

const NUMERIC_VALUE_PATTERN = /^-?\d+(\.\d+)?$/

export function parseFunctionNameFromExpression(expression: unknown): string {
  if (typeof expression !== 'string' || !expression) return ''
  const match = expression.match(/^([a-z_][\w.]*)\s*\(/i)
  return match ? match[1] : ''
}

export function findFunctionByName(
  functionName: string,
  functions: readonly AviatorFunction[],
): AviatorFunction | null {
  if (!functionName) return null
  return functions.find((item) => item.name === functionName) || null
}

export function formatFunctionParameterValue(value: NodeValue, type: 'field' | 'value' | 'expression'): NodeValue {
  if (type === 'field') {
    return value
  }

  if (typeof value === 'string' && !NUMERIC_VALUE_PATTERN.test(value)) {
    return `"${value}"`
  }

  return value
}
