import type { NodeValue } from '../../infrastructure/engine/types'

interface BasicValueActionOptions {
  emitUpdateValue: (value: NodeValue) => void
}

export function createBasicValueActions(options: BasicValueActionOptions) {
  const { emitUpdateValue } = options

  const updateValue = (value: NodeValue) => {
    emitUpdateValue(value)
  }

  const updateMultiValue = (values: string[]) => {
    emitUpdateValue(values)
  }

  const updateFormatValue = (value: NodeValue) => {
    emitUpdateValue(value)
  }

  const updateTimezoneValue = (value: NodeValue) => {
    emitUpdateValue(value)
  }

  return {
    updateValue,
    updateMultiValue,
    updateFormatValue,
    updateTimezoneValue,
  }
}
