import { createConditionNodeViewListeners } from './listeners'
import { createConditionNodeMode } from './mode'
import type { UseConditionNodeViewBindingsOptions } from './types'

export function setupConditionNodeViewBindings(options: UseConditionNodeViewBindingsOptions) {
  const { props, emit } = options

  const conditionNodeMode = createConditionNodeMode(props)
  const listeners = createConditionNodeViewListeners(emit)

  return {
    conditionNodeMode,
    listeners,
  }
}
