import type { setupParameterModeConditionBindings } from './setup'

interface CreateParameterModeConditionExposedBindingsOptions {
  setupResult: ReturnType<typeof setupParameterModeConditionBindings>
}

export function createParameterModeConditionExposedBindings(
  options: CreateParameterModeConditionExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    conditionTreeListeners: setupResult.listeners.conditionTreeListeners,
  }
}
