import type { FunctionParameter, NodeValue, TreeNode } from '../../infrastructure/engine/types'
import type { useParameterInputControllerState } from './useParameterInputController.state'
import type { UseParameterInputControllerOptions } from './useParameterInputController.types'

export type ParameterInputControllerState = ReturnType<typeof useParameterInputControllerState>

export type UseParameterInputControllerActionsOptions = Pick<
  UseParameterInputControllerOptions,
  'props' | 'emitUpdateValue' | 'emitUpdateType' | 'emitUpdateValueDataType'
>

export function resolveNestedTreeNode(
  parameter: FunctionParameter,
  value: NodeValue,
): TreeNode | null {
  const source = parameter.nestedNode ?? value
  if (!source || typeof source !== 'object') return null
  if (!('id' in source) || !('type' in source)) return null
  return source as TreeNode
}
