import { computed } from 'vue'
import type { ParameterInputProps } from './useParameterInputController.types'

export function createParameterInputControllerDisplayValue(props: ParameterInputProps) {
  return computed(() => {
    if (props.value && typeof props.value === 'object' && props.value.id && props.value.type) {
      return ''
    }
    return props.value
  })
}
