import type { setupConditionTreeEditorBindings } from './setup'

interface CreateConditionTreeEditorExposedBindingsOptions {
  setupResult: ReturnType<typeof setupConditionTreeEditorBindings>
}

export function createConditionTreeEditorExposedBindings(
  options: CreateConditionTreeEditorExposedBindingsOptions,
) {
  return {
    conditionTreeListeners: options.setupResult.listeners.conditionTreeListeners,
  }
}
