import { createNodeActionsExposedBindings } from './node-actions-bindings/exposed'
import { setupNodeActionsBindings } from './node-actions-bindings/setup'
import type { UseNodeActionsBindingsOptions } from './node-actions-bindings/types'

export type {
  NodeActionsEmits,
  NodeActionsProps,
  UseNodeActionsBindingsOptions,
} from './node-actions-bindings/types'

export function useNodeActionsBindings(options: UseNodeActionsBindingsOptions) {
  const setupResult = setupNodeActionsBindings(options)
  return createNodeActionsExposedBindings({ setupResult })
}
