const DEFAULT_URL_ERROR = 'URL格式不正确，请输入有效的URL地址'

const ALLOWED_PROTOCOLS = new Set(['http:', 'https:', 'ftp:'])

export function validateUrlInput(value: unknown): string {
  if (typeof value !== 'string' || !value) {
    return ''
  }

  try {
    const parsed = new URL(value)
    if (!ALLOWED_PROTOCOLS.has(parsed.protocol)) {
      return 'URL协议必须是 http、https 或 ftp'
    }
    return ''
  } catch {
    if (!value.includes('://')) {
      try {
        new URL(`http://${value}`)
        return ''
      } catch {
        return DEFAULT_URL_ERROR
      }
    }
    return DEFAULT_URL_ERROR
  }
}
