import { createTreeExpressionBuilderPreviewListeners } from './listeners.preview'
import { createTreeExpressionBuilderToolbarListeners } from './listeners.toolbar'
import { createTreeExpressionBuilderTreeCanvasListeners } from './listeners.tree-canvas'
import type { TreeExpressionBuilderBindingsController } from './types'

interface CreateTreeExpressionBuilderListenersOptions {
  controller: TreeExpressionBuilderBindingsController
}

export function createTreeExpressionBuilderListeners(options: CreateTreeExpressionBuilderListenersOptions) {
  const { controller } = options
  const toolbarListeners = createTreeExpressionBuilderToolbarListeners(controller)
  const treeCanvasListeners = createTreeExpressionBuilderTreeCanvasListeners(controller)
  const expressionPreviewListeners = createTreeExpressionBuilderPreviewListeners(controller)

  return {
    toolbarListeners,
    treeCanvasListeners,
    expressionPreviewListeners,
  }
}
