import type { setupFieldRefEditorBindings } from './setup'

interface CreateFieldRefEditorExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFieldRefEditorBindings>
}

export function createFieldRefEditorExposedBindings(options: CreateFieldRefEditorExposedBindingsOptions) {
  const { state, resolvers, forwarders } = options.setupResult

  return {
    currentFieldValue: state.currentFieldValue,
    isArrayField: state.isArrayField,
    resolveFieldTooltip: resolvers.resolveFieldTooltip,
    resolveTypeColor: resolvers.resolveTypeColor,
    onUpdateField: forwarders.onUpdateField,
  }
}
