import type { NodeValue } from '../../../../infrastructure/engine/types'
import type { FunctionParameterUpdatePayload } from '../editors/function-ref/types'

interface ValueInputViewListenerHandlers {
  changeValueType: (type: string) => void
  updateValue: (value: NodeValue) => void
  updateMultiValues: (values: string[]) => void
  updateDateValue: (date: Date | undefined) => void
  validateURL: () => void
  changeValueDataType: (dataType: string) => void
  updateBaseField: (fieldName: string) => void
  updateValueArrayIndex: (index: number | undefined) => void
  updateFunction: (functionName: string) => void
  onUpdateParameter: (payload: FunctionParameterUpdatePayload) => void
}

export function createValueInputViewListeners(handlers: ValueInputViewListenerHandlers) {
  const switchPanelListeners = {
    'update:type': handlers.changeValueType,
    'update:value': handlers.updateValue,
    'update:multi-values': handlers.updateMultiValues,
    'update:date-value': handlers.updateDateValue,
    'blur:url': handlers.validateURL,
    'update:value-data-type': handlers.changeValueDataType,
    'update:field': handlers.updateBaseField,
    'update:array-index': handlers.updateValueArrayIndex,
    'update:function': handlers.updateFunction,
    'update:parameter': handlers.onUpdateParameter,
  }

  return {
    switchPanelListeners,
  }
}
