import type { ValueInputSwitchPanelEmits } from '../types'

export function createValueFieldForwarders(emit: ValueInputSwitchPanelEmits) {
  const onUpdateField = (value: string) => emit('update:field', value)
  const onUpdateArrayIndex = (index: number | undefined) => emit('update:array-index', index)

  return {
    onUpdateField,
    onUpdateArrayIndex,
  }
}
