import type { Ref } from 'vue'
import type { AviatorFunction, NodeValue } from '../../../infrastructure/engine/types'
import { findFunctionByName, formatFunctionParameterValue } from '../../logic/value-input'
import { createFunctionParameters, findFunctionByExpression } from './helpers'
import type { FunctionRefParameter } from './types'

interface CreateFunctionRefValueActionsOptions {
  functions: readonly AviatorFunction[]
  selectedFunctionName: Ref<string>
  functionParameters: Ref<FunctionRefParameter[]>
  selectedFunction: Readonly<Ref<AviatorFunction | null>>
}

export function createFunctionRefValueActions(options: CreateFunctionRefValueActionsOptions) {
  const { functions, selectedFunctionName, functionParameters, selectedFunction } = options

  const initializeFromExpression = (expression: unknown): boolean => {
    const func = findFunctionByExpression(expression, functions)
    if (!func) {
      return false
    }

    selectedFunctionName.value = func.name
    functionParameters.value = createFunctionParameters(func)
    return true
  }

  const buildExpression = (): string => {
    if (!selectedFunction.value) {
      return ''
    }

    const params = functionParameters.value
      .filter((param) => param.value !== undefined && param.value !== '')
      .map((param) => formatFunctionParameterValue(param.value, param.type))
      .join(', ')

    return `${selectedFunction.value.name}(${params})`
  }

  const selectFunction = (functionName: string): string => {
    const func = findFunctionByName(functionName, functions)
    if (!func) {
      return ''
    }

    selectedFunctionName.value = functionName
    functionParameters.value = createFunctionParameters(func)
    return buildExpression()
  }

  const setParameter = (index: number, value: NodeValue): string => {
    if (!functionParameters.value[index]) {
      return buildExpression()
    }

    functionParameters.value[index] = {
      ...functionParameters.value[index],
      value,
    }

    return buildExpression()
  }

  return {
    initializeFromExpression,
    buildExpression,
    selectFunction,
    setParameter,
  }
}
