import { computed, ref } from 'vue'
import type { ExpressionValidationResult, UiError } from './useTreeExpressionBuilder.types'
import type {
  TreeExpressionBuilderCoreOptions,
  TreeExpressionBuilderValidationRefs,
} from './useTreeExpressionBuilderState.shared'

export function useTreeExpressionBuilderValidationState(options: TreeExpressionBuilderCoreOptions) {
  const { service, rootNodes } = options

  const parseError = ref<string | null>(null)
  const validationErrors = ref<UiError[]>([])
  const validating = ref(false)
  const validationResult = ref<ExpressionValidationResult | null>(null)

  const allErrors = computed<UiError[]>(() => {
    const errors: UiError[] = []
    if (parseError.value) {
      errors.push({ nodeId: 'root', message: parseError.value })
    }
    errors.push(...validationErrors.value)
    return errors
  })

  const runValidation = () => {
    validationErrors.value = service.validate(rootNodes.value)
  }

  const validationRefs: TreeExpressionBuilderValidationRefs = {
    parseError,
    validationErrors,
    validating,
    validationResult,
  }

  return {
    parseError: validationRefs.parseError,
    validationErrors: validationRefs.validationErrors,
    validating: validationRefs.validating,
    validationResult: validationRefs.validationResult,
    allErrors,
    runValidation,
  }
}
