import type { useFunctionModeEditorControllerFilterActions } from './useFunctionModeEditorController.filterActions'
import type { useFunctionModeEditorControllerUsageActions } from './useFunctionModeEditorController.usageActions'

interface CreateFunctionModeEditorControllerActionsExposedOptions {
  filterActions: ReturnType<typeof useFunctionModeEditorControllerFilterActions>
  usageActions: ReturnType<typeof useFunctionModeEditorControllerUsageActions>
}

export function createFunctionModeEditorControllerActionsExposed(
  options: CreateFunctionModeEditorControllerActionsExposedOptions,
) {
  const { filterActions, usageActions } = options

  return {
    filterFunctionOption: filterActions.filterFunctionOption,
    showFunctionUsage: usageActions.showFunctionUsage,
  }
}
