export const normalizeType = (type?: string): string => {
  if (!type) {
    return ''
  }
  return String(type).toLowerCase()
}

export const isCollectionType = (type: string): boolean => ['list', 'array', 'set'].includes(type)

export const isReturnTypeCompatible = (actualType: string, expectedType: string): boolean => {
  if (!actualType || !expectedType) {
    return false
  }
  if (actualType === expectedType) {
    return true
  }
  return isCollectionType(actualType) && isCollectionType(expectedType)
}
