import type { TreeExpressionBuilderNotifier } from './treeExpressionBuilderNotifier'
import type { TreeExpressionBuilderState } from './useTreeExpressionBuilderExpressionActions.shared'

interface ClipboardActions {
  copyExpression: () => Promise<void>
}

export function createTreeExpressionBuilderClipboardActions(
  state: TreeExpressionBuilderState,
  notifier: TreeExpressionBuilderNotifier,
): ClipboardActions {
  const copyExpression = async () => {
    if (!state.generatedExpression.value) {
      notifier.warning('当前没有可复制的表达式')
      return
    }

    try {
      await navigator.clipboard.writeText(state.generatedExpression.value)
      notifier.success('表达式已复制')
    } catch {
      notifier.error('复制失败')
    }
  }

  return {
    copyExpression,
  }
}
