import { createTreeNodeChildrenForwarders } from './children-bindings/forwarders'
import { createTreeNodeChildrenListeners } from './children-bindings/listeners'
import type { UseTreeNodeChildrenBindingsOptions } from './children-bindings/types'

export type { UseTreeNodeChildrenBindingsOptions } from './children-bindings/types'

export function useTreeNodeChildrenBindings(options: UseTreeNodeChildrenBindingsOptions) {
  const bindings = createTreeNodeChildrenForwarders(options)

  return {
    childNodeListeners: createTreeNodeChildrenListeners({ bindings }).childNodeListeners,
  }
}
