import { createParameterInputControllerActionsExposed } from './useParameterInputController.actions.exposed'
import { createParameterInputNestedActions } from './useParameterInputController.actions.nested'
import type {
  ParameterInputControllerState,
  UseParameterInputControllerActionsOptions,
} from './useParameterInputController.actions.shared'
import { createParameterInputValueActions } from './useParameterInputController.actions.value'

export function useParameterInputControllerActions(
  state: ParameterInputControllerState,
  options: UseParameterInputControllerActionsOptions,
) {
  const valueActions = createParameterInputValueActions(state, options)
  const nestedActions = createParameterInputNestedActions(options)

  return createParameterInputControllerActionsExposed({
    valueActions,
    nestedActions,
  })
}
