import type { setupValueInputViewBindings } from './setup'

interface CreateValueInputViewExposedOptions {
  setupResult: ReturnType<typeof setupValueInputViewBindings>
}

export function createValueInputViewExposed(options: CreateValueInputViewExposedOptions) {
  const {
    isCompoundOperator,
    listeners,
    switchPanelProps,
  } = options.setupResult

  return {
    isCompoundOperator,
    switchPanelProps,
    switchPanelListeners: listeners.switchPanelListeners,
  }
}
