import { createConditionNode } from '../../infrastructure/engine/utils'
import {
  resolveFieldModeValue,
  resolveLambdaModeValue,
  resolveValueModeValue,
} from '../logic/parameterInputValueTransitions'
import type {
  ParameterInputControllerState,
  UseParameterInputControllerActionsOptions,
} from './useParameterInputController.actions.shared'

export function createChangeParameterTypeAction(
  state: ParameterInputControllerState,
  options: UseParameterInputControllerActionsOptions,
) {
  const { props, emitUpdateType, emitUpdateValue } = options

  return (type: string) => {
    state.userSelectedType.value = type
    emitUpdateType(props.parameter.name, type)

    if (type === 'value') {
      emitUpdateValue(resolveValueModeValue({
        savedStringValue: state.savedStringValue.value,
        currentValue: props.value,
      }))
      return
    }

    if (type === 'field') {
      emitUpdateValue(resolveFieldModeValue(props.value, props.availableFields))
      return
    }

    if (type === 'condition') {
      emitUpdateValue(createConditionNode(undefined, 1))
      return
    }

    emitUpdateValue(resolveLambdaModeValue(props.value))
  }
}
