import { computed } from 'vue'
import type { NodeValue } from '../../../../infrastructure/engine/types'

interface CreateValueInputViewStateOptions {
  controller: {
    getValueInputType: () => string
    getAvailableValueTypes: () => Array<{ value: string, label: string }>
    generateFunctionExpression: () => string
    updateParameter: (index: number, value: NodeValue) => void
  }
}

export function createValueInputViewState(options: CreateValueInputViewStateOptions) {
  const { controller } = options

  const currentInputType = computed(() => controller.getValueInputType())
  const valueTypeOptions = computed(() => controller.getAvailableValueTypes())
  const functionExpression = computed(() => controller.generateFunctionExpression())

  const onUpdateParameter = ({ index, value }: { index: number, value: NodeValue }) => {
    controller.updateParameter(index, value)
  }

  return {
    currentInputType,
    valueTypeOptions,
    functionExpression,
    onUpdateParameter,
  }
}
