import { createFieldModeFieldSelectExposedBindings } from './field-mode-field-select-bindings/exposed'
import { setupFieldModeFieldSelectBindings } from './field-mode-field-select-bindings/setup'
import type {
  UseFieldModeFieldSelectBindingsOptions,
} from './field-mode-field-select-bindings/types'

export type {
  FieldModeFieldSelectEmits,
  FieldModeFieldSelectProps,
  UseFieldModeFieldSelectBindingsOptions,
} from './field-mode-field-select-bindings/types'

export function useFieldModeFieldSelectBindings(options: UseFieldModeFieldSelectBindingsOptions) {
  const setupResult = setupFieldModeFieldSelectBindings(options)
  return createFieldModeFieldSelectExposedBindings({ setupResult })
}
