import type { setupValueInputSwitchPanelBindings } from './setup'

interface CreateValueInputSwitchPanelExposedBindingsOptions {
  setupResult: ReturnType<typeof setupValueInputSwitchPanelBindings>
}

export function createValueInputSwitchPanelExposedBindings(
  options: CreateValueInputSwitchPanelExposedBindingsOptions,
) {
  return {
    selectorProps: options.setupResult.panelProps.selectorProps,
    panelBodyProps: options.setupResult.panelProps.panelBodyProps,
    typeSelectorListeners: options.setupResult.listeners.typeSelectorListeners,
    panelBodyListeners: options.setupResult.listeners.panelBodyListeners,
  }
}
