import type { TreeNode } from '../../types'

function moveNodeBySiblingOffset(nodes: TreeNode[], nodeId: string, offset: -1 | 1): boolean {
  const moveInArray = (items: TreeNode[]): boolean => {
    const index = items.findIndex((node) => node.id === nodeId)
    const targetIndex = index + offset
    if (index >= 0 && targetIndex >= 0 && targetIndex < items.length) {
      const temp = items[index]
      items[index] = items[targetIndex]
      items[targetIndex] = temp
      return true
    }

    for (const node of items) {
      if (node.children && moveInArray(node.children)) {
        return true
      }
    }

    return false
  }

  return moveInArray(nodes)
}

export function moveNodeUp(nodes: TreeNode[], nodeId: string): boolean {
  return moveNodeBySiblingOffset(nodes, nodeId, -1)
}

export function moveNodeDown(nodes: TreeNode[], nodeId: string): boolean {
  return moveNodeBySiblingOffset(nodes, nodeId, 1)
}
