import type {
  UseValueInputControllerActionsOptions,
  ValueInputControllerState,
} from './useValueInputController.shared'

export function useValueInputControllerFieldActions(
  state: ValueInputControllerState,
  options: UseValueInputControllerActionsOptions,
) {
  const { props, emitUpdateValue } = options

  const updateBaseField = (value: string) => {
    if (!props.availableFields) return

    const field = props.availableFields.find((item) => item.value === value)
    let finalValue = value

    if (field?.type === 'array' && !/\[\d+\]$/.test(value)) {
      finalValue = `${value}[0]`
    }

    emitUpdateValue(finalValue)
  }

  const updateValueArrayIndex = (index: number | undefined) => {
    const baseFieldName = state.getBaseFieldName()
    if (!baseFieldName) return

    const newValue = index !== undefined ? `${baseFieldName}[${index}]` : baseFieldName
    emitUpdateValue(newValue)
  }

  return {
    updateBaseField,
    updateValueArrayIndex,
  }
}
