import { createTreeExpressionBuilderExposedBindings } from './tree-expression-builder-bindings/exposed'
import { setupTreeExpressionBuilderBindings } from './tree-expression-builder-bindings/setup'
import type { UseTreeExpressionBuilderBindingsOptions } from './tree-expression-builder-bindings/types'

export type { UseTreeExpressionBuilderBindingsOptions } from './tree-expression-builder-bindings/types'

export function useTreeExpressionBuilderBindings(options: UseTreeExpressionBuilderBindingsOptions) {
  const setupResult = setupTreeExpressionBuilderBindings(options)
  return createTreeExpressionBuilderExposedBindings({ setupResult })
}
