import type { createParameterInputModeFlags } from './view-model-modes'
import type { createParameterInputModeProps } from './view-model-mode-props'
import type { createParameterInputSelectorViewModel } from './view-model-selector'

interface CreateParameterInputViewModelExposedOptions {
  selectorViewModel: ReturnType<typeof createParameterInputSelectorViewModel>
  modeFlags: ReturnType<typeof createParameterInputModeFlags>
  modeProps: ReturnType<typeof createParameterInputModeProps>
}

export function createParameterInputViewModelExposed(
  options: CreateParameterInputViewModelExposedOptions,
) {
  const { selectorViewModel, modeFlags, modeProps } = options

  return {
    selectorKey: selectorViewModel.selectorKey,
    selectorProps: selectorViewModel.selectorProps,
    isValueMode: modeFlags.isValueMode,
    isFieldMode: modeFlags.isFieldMode,
    isConditionMode: modeFlags.isConditionMode,
    isLambdaMode: modeFlags.isLambdaMode,
    valueModeProps: modeProps.valueModeProps,
    fieldModeProps: modeProps.fieldModeProps,
    conditionModeProps: modeProps.conditionModeProps,
    lambdaModeProps: modeProps.lambdaModeProps,
  }
}
