import type { createTreeNodeViewForwarders } from '../useTreeNodeViewBindings.forwarders'
import type { createTreeNodeViewHandlers } from '../useTreeNodeViewBindings.handlers'
import type { createTreeNodeControllerBindings } from './controller'

interface CreateTreeNodeContentListenersOptions {
  controller: ReturnType<typeof createTreeNodeControllerBindings>
  handlers: ReturnType<typeof createTreeNodeViewHandlers>
  forwarders: ReturnType<typeof createTreeNodeViewForwarders>
}

export function createTreeNodeContentListeners(options: CreateTreeNodeContentListenersOptions) {
  const { controller, handlers, forwarders } = options

  return {
    'toggle-expanded': controller.toggleExpanded,
    'drag-start': controller.handleDragStart,
    'drag-end': controller.handleDragEnd,
    'update:condition-negation': controller.updateConditionNegation,
    'switch:mode': controller.switchConditionMode,
    'update:field': controller.updateBaseField,
    'update:array-index': controller.updateArrayIndex,
    'update:comparison': controller.updateComparison,
    'update:value': controller.updateValue,
    'update:extra-comparison': controller.updateExtraComparison,
    'update:value-data-type': handlers.onConditionValueDataType,
    'update:function': controller.updateFunction,
    'update:parameter': handlers.onParameterUpdate,
    'update:parameter-type': handlers.onParameterTypeUpdate,
    'update:parameter-value-type': handlers.onParameterValueTypeUpdate,
    'update:function-value-data-type': handlers.onFunctionValueDataType,
    'update:group-operator': controller.updateOperator,
    'update:group-negation': controller.updateGroupNegation,
    'add-child': forwarders.forwardAddChild,
    'move-up': forwarders.forwardMoveUp,
    'move-down': forwarders.forwardMoveDown,
    'copy-node': controller.copyNode,
    'remove-node': forwarders.forwardRemoveNode,
  } as const
}
