import { createParameterInputExposedBindings } from './parameter-input-bindings/exposed'
import { setupParameterInputBindings } from './parameter-input-bindings/setup'
import type { UseParameterInputBindingsOptions } from './parameter-input-bindings/types'

export type {
  ParameterInputEmits,
  UseParameterInputBindingsOptions,
} from './parameter-input-bindings/types'

export function useParameterInputBindings(options: UseParameterInputBindingsOptions) {
  const setupResult = setupParameterInputBindings(options)
  return createParameterInputExposedBindings({ setupResult })
}
