import type { NodeValue } from '../../infrastructure/engine/types'
import type {
  UseValueInputControllerActionsOptions,
  ValueInputControllerState,
} from './useValueInputController.shared'

export function useValueInputControllerFunctionActions(
  state: ValueInputControllerState,
  options: UseValueInputControllerActionsOptions,
) {
  const { emitUpdateValue } = options

  const updateFunction = (functionName: string) => {
    const expression = state.functionRefController.selectFunction(functionName)
    if (!expression) return
    emitUpdateValue(expression)
  }

  const updateParameter = (index: number, value: NodeValue) => {
    const expression = state.functionRefController.setParameter(index, value)
    emitUpdateValue(expression)
  }

  const generateFunctionExpression = () => {
    return state.functionRefController.buildExpression()
  }

  return {
    updateFunction,
    updateParameter,
    generateFunctionExpression,
  }
}
