import type { FieldOption, FunctionParameter } from '../../../infrastructure/engine/types'
import type { ParameterInputType } from './constants'
import { isFieldValue, isLambdaValue, isParameterInputType, isTreeNodeLike, resolveRawType } from './helpers'

interface ResolveParameterInputTypeParams {
  explicitType?: string | null
  parameter: FunctionParameter
  value: unknown
  availableFields: FieldOption[]
  isLambdaParameter: boolean
}

export function resolveParameterInputType(params: ResolveParameterInputTypeParams): ParameterInputType {
  const { explicitType, parameter, value, availableFields, isLambdaParameter } = params

  if (explicitType && isParameterInputType(explicitType)) {
    return explicitType
  }

  if (isTreeNodeLike(value)) {
    return 'condition'
  }

  if (parameter.type && ['field', 'value', 'expression', 'condition', 'lambda'].includes(parameter.type)) {
    if (parameter.type === 'expression') {
      return 'condition'
    }
    return parameter.type as ParameterInputType
  }

  if (resolveRawType(parameter) === 'function') {
    return 'condition'
  }

  if (isLambdaParameter && (!value || isLambdaValue(value))) {
    return 'lambda'
  }

  if (isFieldValue(value, availableFields)) {
    return 'field'
  }

  return 'value'
}
