import type { TreeNode } from '../../../infrastructure/engine/types'
import type { BuilderNodeType } from '../../types/treeInteraction'
import type { TreeNodeDragPosition, TreeNodeViewEmits } from './types'

export function createTreeNodeViewForwarders(emit: TreeNodeViewEmits) {
  const forwardUpdateNode = (nodeId: string, updates: Partial<TreeNode>) => {
    emit('update-node', nodeId, updates)
  }

  const forwardAddChild = (parentId: string, nodeType: BuilderNodeType) => {
    emit('add-child', parentId, nodeType)
  }

  const forwardRemoveNode = (nodeId: string) => {
    emit('remove-node', nodeId)
  }

  const forwardMoveUp = (nodeId: string) => {
    emit('move-up', nodeId)
  }

  const forwardMoveDown = (nodeId: string) => {
    emit('move-down', nodeId)
  }

  const forwardCopyNode = (nodeId: string) => {
    emit('copy-node', nodeId)
  }

  const forwardUpdateParameterType = (paramName: string, type: string) => {
    emit('update-parameter-type', paramName, type)
  }

  const forwardUpdateParameterValueDataType = (nodeId: string, paramName: string, dataType: string) => {
    emit('update-parameter-value-data-type', nodeId, paramName, dataType)
  }

  const forwardDragNode = (sourceNodeId: string, targetNodeId: string, position: TreeNodeDragPosition) => {
    emit('drag-node', sourceNodeId, targetNodeId, position)
  }

  return {
    forwardUpdateNode,
    forwardAddChild,
    forwardRemoveNode,
    forwardMoveUp,
    forwardMoveDown,
    forwardCopyNode,
    forwardUpdateParameterType,
    forwardUpdateParameterValueDataType,
    forwardDragNode,
  }
}
