import { ref } from 'vue'
import type { TreeNode } from '../../infrastructure/engine/types'
import { createAviatorExpressionService } from '../../application/services/aviator-expression-service'
import type { UseTreeExpressionBuilderControllerOptions } from './useTreeExpressionBuilder.types'
import { useTreeExpressionBuilderExpressionState } from './useTreeExpressionBuilderState.expression'
import { useTreeExpressionBuilderFieldState } from './useTreeExpressionBuilderState.fields'
import { useTreeExpressionBuilderValidationState } from './useTreeExpressionBuilderState.validation'

export type SetupTreeExpressionBuilderStateOptions = Pick<
  UseTreeExpressionBuilderControllerOptions,
  'props' | 'emitUpdateModelValue'
>

export function setupTreeExpressionBuilderState(options: SetupTreeExpressionBuilderStateOptions) {
  const { props, emitUpdateModelValue } = options

  const service = createAviatorExpressionService({ availableFields: [] })
  const parameterDataTypes = service.getParameterDataTypes()
  const rootNodes = ref<TreeNode[]>([])

  const fieldState = useTreeExpressionBuilderFieldState({
    props,
    service,
    rootNodes,
  })

  const validationState = useTreeExpressionBuilderValidationState({
    props,
    service,
    rootNodes,
  })

  const expressionState = useTreeExpressionBuilderExpressionState({
    props,
    service,
    rootNodes,
    emitUpdateModelValue,
    syncServiceFields: fieldState.syncServiceFields,
    runValidation: validationState.runValidation,
    validationRefs: {
      parseError: validationState.parseError,
      validationErrors: validationState.validationErrors,
      validating: validationState.validating,
      validationResult: validationState.validationResult,
    },
  })

  return {
    service,
    parameterDataTypes,
    rootNodes,
    fieldState,
    validationState,
    expressionState,
  }
}
