import { useTreeNodeFieldMutation } from './useTreeNodeFieldMutation'
import { useTreeNodeMutationCondition } from './useTreeNodeMutation.condition'
import { createTreeNodeMutationExposed } from './useTreeNodeMutation.exposed'
import type { UseTreeNodeMutationOptions } from './useTreeNodeMutation.shared'
import { useTreeNodeMutationUi } from './useTreeNodeMutation.ui'
import { useTreeNodeParameterMutation } from './useTreeNodeParameterMutation'

export function useTreeNodeMutation(options: UseTreeNodeMutationOptions) {
  const {
    props,
    emitUpdateNode,
    emitCopyNode,
    emitUpdateParameterType,
    emitUpdateParameterValueDataType,
  } = options

  const fieldMutation = useTreeNodeFieldMutation({
    props,
    emitUpdateNode,
    emitUpdateParameterValueDataType,
  })

  const parameterMutation = useTreeNodeParameterMutation({
    props,
    emitUpdateNode,
    emitUpdateParameterType,
    emitUpdateParameterValueDataType,
  })

  const uiMutation = useTreeNodeMutationUi({
    props,
    emitUpdateNode,
    emitCopyNode,
  })

  const conditionMutation = useTreeNodeMutationCondition({
    props,
    emitUpdateNode,
    emitUpdateParameterValueDataType,
    getFieldType: fieldMutation.getFieldType,
  })

  return createTreeNodeMutationExposed({
    uiMutation,
    fieldMutation,
    conditionMutation,
    parameterMutation,
  })
}
