import { computed } from 'vue'
import { useFieldModeEditorController } from '../../../composables/useFieldModeEditorController'
import { createFieldModeEditorListeners } from './listeners'
import type { UseFieldModeEditorBindingsOptions } from './types'

export function setupFieldModeEditorBindings(options: UseFieldModeEditorBindingsOptions) {
  const { props, emit } = options

  const controller = useFieldModeEditorController({
    props,
    emitUpdateField: (value) => emit('update:field', value),
    emitUpdateValueDataType: (data) => emit('update:value-data-type', data),
  })

  const currentDataType = computed(() => {
    if (!props.getParameterDataType) return 'string'
    return props.getParameterDataType(props.node.id, 'condition_value')
  })

  const listeners = createFieldModeEditorListeners({
    emit,
    handleFieldChange: controller.handleFieldChange,
  })

  return {
    controller,
    currentDataType,
    listeners,
  }
}
