import type { setupTreeCanvasBindings } from './setup'

interface CreateTreeCanvasExposedBindingsOptions {
  setupResult: ReturnType<typeof setupTreeCanvasBindings>
}

export function createTreeCanvasExposedBindings(options: CreateTreeCanvasExposedBindingsOptions) {
  const { listeners } = options.setupResult

  return {
    nodeListeners: listeners.nodeListeners,
    emptyStateButtonListeners: listeners.emptyStateButtonListeners,
  }
}
