import type { ComputedRef } from 'vue'
import type { FieldOption } from '../../infrastructure/engine/types'
import { shouldBeLambdaParameter } from '../../infrastructure/engine/utils'
import {
  buildAvailableParameterTypes,
  getParameterFieldTooltip,
  getParameterTypeColor,
  resolveParameterInputType,
  toStringArrayValue,
} from '../logic/parameter-input'
import type { ParameterInputProps } from './useParameterInputController.types'
import type { ParameterInputControllerStateRefs } from './useParameterInputController.state.refs'

interface CreateParameterInputControllerStateQueriesOptions {
  props: ParameterInputProps
  refs: ParameterInputControllerStateRefs
  displayValue: ComputedRef<unknown>
}

export function createParameterInputControllerStateQueries(options: CreateParameterInputControllerStateQueriesOptions) {
  const { props, refs, displayValue } = options

  const isCurrentLambdaParameter = () => {
    const currentFunctionName = props.functionName || ''
    return shouldBeLambdaParameter(currentFunctionName, props.parameter.name, props.parameter.description)
  }

  const getParameterInputType = () => {
    return resolveParameterInputType({
      explicitType: refs.userSelectedType.value,
      parameter: props.parameter,
      value: props.value,
      availableFields: props.availableFields,
      isLambdaParameter: isCurrentLambdaParameter(),
    })
  }

  const getAvailableParameterTypes = () => {
    return buildAvailableParameterTypes(isCurrentLambdaParameter())
  }

  const getMultiValue = () => toStringArrayValue(displayValue.value)

  const getTypeColor = (type: string) => getParameterTypeColor(type)

  const getFieldTooltipText = (field: FieldOption) => getParameterFieldTooltip(field)

  const getValueDataType = () => {
    if (refs.userHasSelectedDataType.value && refs.userSelectedValueDataType.value) {
      return refs.userSelectedValueDataType.value
    }

    if (props.currentDataType) {
      return props.currentDataType
    }

    if (props.parameter.valueType) {
      return props.parameter.valueType
    }

    return 'string'
  }

  return {
    isCurrentLambdaParameter,
    getParameterInputType,
    getAvailableParameterTypes,
    getMultiValue,
    getTypeColor,
    getFieldTooltipText,
    getValueDataType,
  }
}
