export interface FieldRefEditorEmitters {
  emitUpdateField: (value: string) => void
}

export function createFieldRefForwarders(options: FieldRefEditorEmitters) {
  const { emitUpdateField } = options

  const onUpdateField = (value: string) => {
    emitUpdateField(value)
  }

  return {
    onUpdateField,
  }
}
