import type { UseConditionModeRadioBindingsOptions } from './types'

export function setupConditionModeRadioBindings(options: UseConditionModeRadioBindingsOptions) {
  const { emit } = options

  const radioGroupListeners = {
    'update:model-value': (mode: 'condition' | 'function') => emit('update:modelValue', mode),
  } as const

  return {
    radioGroupListeners,
  }
}
