import type { setupParameterInputBindings } from './setup'

interface CreateParameterInputExposedBindingsOptions {
  setupResult: ReturnType<typeof setupParameterInputBindings>
}

export function createParameterInputExposedBindings(options: CreateParameterInputExposedBindingsOptions) {
  const {
    listeners,
    viewModel,
  } = options.setupResult

  return {
    selectorKey: viewModel.selectorKey,
    selectorProps: viewModel.selectorProps,
    isValueMode: viewModel.isValueMode,
    isFieldMode: viewModel.isFieldMode,
    isConditionMode: viewModel.isConditionMode,
    isLambdaMode: viewModel.isLambdaMode,
    valueModeProps: viewModel.valueModeProps,
    fieldModeProps: viewModel.fieldModeProps,
    conditionModeProps: viewModel.conditionModeProps,
    lambdaModeProps: viewModel.lambdaModeProps,
    typeSelectorListeners: listeners.typeSelectorListeners,
    valueModeListeners: listeners.valueModeListeners,
    fieldModeListeners: listeners.fieldModeListeners,
    conditionModeListeners: listeners.conditionModeListeners,
    lambdaModeListeners: listeners.lambdaModeListeners,
  }
}
