import type { useParameterInputControllerActions } from './useParameterInputController.actions'
import type { useParameterInputControllerState } from './useParameterInputController.state'

type ParameterInputControllerState = ReturnType<typeof useParameterInputControllerState>
type ParameterInputControllerActions = ReturnType<typeof useParameterInputControllerActions>

export function buildParameterInputControllerExposed(
  state: ParameterInputControllerState,
  actions: ParameterInputControllerActions,
) {
  return {
    getParameterInputType: state.getParameterInputType,
    getAvailableParameterTypes: state.getAvailableParameterTypes,
    displayValue: state.displayValue,
    updateValue: actions.updateValue,
    updateMultiValue: actions.updateMultiValue,
    updateFormatValue: actions.updateFormatValue,
    updateTimezoneValue: actions.updateTimezoneValue,
    getMultiValue: state.getMultiValue,
    getTypeColor: state.getTypeColor,
    getFieldTooltipText: state.getFieldTooltipText,
    getValueDataType: state.getValueDataType,
    changeValueDataType: actions.changeValueDataType,
    changeParameterType: actions.changeParameterType,
    updateNestedNode: actions.updateNestedNode,
    updateNestedParameterType: actions.updateNestedParameterType,
  }
}
