import {
  createConditionTreeEventForwarders,
  createConditionTreeListeners,
} from '../../shared/condition-tree-events'
import type { UseParameterModeConditionBindingsOptions } from './types'

export function setupParameterModeConditionBindings(options: UseParameterModeConditionBindingsOptions) {
  const { emit } = options

  const forwarders = createConditionTreeEventForwarders(emit)
  const listeners = createConditionTreeListeners({ forwarders })

  return {
    listeners,
  }
}
