import type { setupTreeExpressionBuilderState } from './useTreeExpressionBuilderState.setup'

interface CreateTreeExpressionBuilderStateExposedOptions {
  setupResult: ReturnType<typeof setupTreeExpressionBuilderState>
}

export function createTreeExpressionBuilderStateExposed(
  options: CreateTreeExpressionBuilderStateExposedOptions,
) {
  const { service, parameterDataTypes, rootNodes, fieldState, validationState, expressionState } = options.setupResult

  return {
    service,
    parameterDataTypes,
    rootNodes,
    generatedExpression: expressionState.generatedExpression,
    validationErrors: validationState.validationErrors,
    parseError: validationState.parseError,
    validating: validationState.validating,
    validationResult: validationState.validationResult,
    extractedFields: fieldState.extractedFields,
    availableFields: fieldState.availableFields,
    dataSourceInfo: fieldState.dataSourceInfo,
    allErrors: validationState.allErrors,
    syncServiceFields: fieldState.syncServiceFields,
    emitExpression: expressionState.emitExpression,
    regenerateExpression: expressionState.regenerateExpression,
    runValidation: validationState.runValidation,
    loadExpression: expressionState.loadExpression,
  }
}
