import { computed } from 'vue'
import type { FunctionRefParameterInputBodyProps } from './input-body.types'

export function createFunctionRefParameterInputBodyState(props: FunctionRefParameterInputBodyProps) {
  const displayDescription = computed(() => props.param.description || props.param.name)
  const fieldPlaceholder = computed(() => `选择${displayDescription.value}`)
  const textPlaceholder = computed(() => `输入${displayDescription.value}`)

  const isFieldType = computed(() => props.param.type === 'field')
  const isValueType = computed(() => props.param.type === 'value')

  return {
    displayDescription,
    fieldPlaceholder,
    textPlaceholder,
    isFieldType,
    isValueType,
  }
}
