<template>
  <ConditionBooleanSelect
    v-if="props.fieldType === 'boolean'"
    v-bind="booleanSelectProps"
    v-on="valueListeners"
  />

  <ConditionNullSelect
    v-else-if="props.isNullComparison"
    v-bind="nullSelectProps"
    v-on="valueListeners"
  />

  <ConditionMultiValueInput
    v-else-if="props.isMultiValue"
    v-bind="multiValueInputProps"
    v-on="multiValueListeners"
  />

  <ConditionUrlInput
    v-else-if="props.fieldType === 'url'"
    v-bind="urlInputProps"
    v-on="urlListeners"
  />

  <ConditionDateTimeInput
    v-else-if="props.fieldType === 'datetime'"
    v-bind="dateTimeInputProps"
    v-on="dateValueListeners"
  />

  <ConditionValueFallbackInput
    v-else
    v-bind="fallbackInputProps"
    v-on="fallbackListeners"
  />
</template>

<script setup lang="ts">
import ConditionBooleanSelect from './ConditionBooleanSelect.vue'
import ConditionDateTimeInput from './ConditionDateTimeInput.vue'
import ConditionMultiValueInput from './ConditionMultiValueInput.vue'
import ConditionValueFallbackInput from './switch/ConditionValueFallbackInput.vue'
import ConditionNullSelect from './ConditionNullSelect.vue'
import ConditionUrlInput from './ConditionUrlInput.vue'
import {
  type ConditionValueInputSwitchEmits,
  type ConditionValueInputSwitchProps,
  useConditionValueInputSwitchBindings,
} from './switch/useConditionValueInputSwitchBindings'

const props = defineProps<ConditionValueInputSwitchProps>()

const emit = defineEmits<ConditionValueInputSwitchEmits>()

const {
  booleanSelectProps,
  nullSelectProps,
  multiValueInputProps,
  urlInputProps,
  dateTimeInputProps,
  fallbackInputProps,
  valueListeners,
  multiValueListeners,
  dateValueListeners,
  urlListeners,
  fallbackListeners,
} = useConditionValueInputSwitchBindings({
  props,
  emit,
})
</script>
