import type { setupFunctionCatalogSelectBindings } from './setup'

interface CreateFunctionCatalogSelectExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionCatalogSelectBindings>
}

export function createFunctionCatalogSelectExposedBindings(
  options: CreateFunctionCatalogSelectExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    selectListeners: setupResult.selectListeners,
  }
}
