import { useFunctionModeEditorControllerActions } from './useFunctionModeEditorController.actions'
import { createFunctionModeEditorControllerExposed } from './useFunctionModeEditorController.exposed'
import { useFunctionModeEditorControllerState } from './useFunctionModeEditorController.state'
import type { UseFunctionModeEditorControllerOptions } from './useFunctionModeEditorController.types'

export type {
  FunctionCategory,
  FunctionModeEditorProps,
  UseFunctionModeEditorControllerOptions,
} from './useFunctionModeEditorController.types'

export function useFunctionModeEditorController(options: UseFunctionModeEditorControllerOptions) {
  const state = useFunctionModeEditorControllerState({ props: options.props })
  const actions = useFunctionModeEditorControllerActions(state)

  return createFunctionModeEditorControllerExposed({
    state,
    actions,
  })
}
