import type { NodeValue } from '../../infrastructure/engine/types'
import {
  createComparisonUpdates,
  createExtraComparisonUpdates,
  createValueUpdates,
} from './useTreeNodeMutation.condition.comparison'
import {
  createConditionModeUpdates,
  createFunctionModeUpdates,
} from './useTreeNodeMutation.condition.defaults'
import { createFunctionSelectionUpdates } from './useTreeNodeMutation.condition.function'
import type { UseTreeNodeMutationOptions } from './useTreeNodeMutation.shared'

export interface UseTreeNodeMutationConditionOptions extends Pick<
  UseTreeNodeMutationOptions,
  'props' | 'emitUpdateNode' | 'emitUpdateParameterValueDataType'
> {
  getFieldType: (fieldName: string) => string
}

export function useTreeNodeMutationCondition(options: UseTreeNodeMutationConditionOptions) {
  const {
    props,
    emitUpdateNode,
    emitUpdateParameterValueDataType,
    getFieldType,
  } = options

  const switchConditionMode = (mode: 'condition' | 'function') => {
    if (mode === 'condition') {
      const conditionModeUpdates = createConditionModeUpdates(
        props.node,
        props.availableFields,
        getFieldType,
      )

      emitUpdateNode(props.node.id, conditionModeUpdates.updates)

      emitUpdateParameterValueDataType(
        props.node.id,
        'condition_value',
        conditionModeUpdates.valueDataType,
      )
      return
    }

    emitUpdateNode(props.node.id, createFunctionModeUpdates())
  }

  const updateComparison = (value: string) => {
    emitUpdateNode(props.node.id, createComparisonUpdates(props.node, value))
  }

  const updateValue = (value: NodeValue) => {
    emitUpdateNode(props.node.id, createValueUpdates(value))
  }

  const updateExtraComparison = (value: string | undefined) => {
    emitUpdateNode(props.node.id, createExtraComparisonUpdates(value))
  }

  const updateFunction = (functionName: string) => {
    const updates = createFunctionSelectionUpdates(functionName)
    if (updates) {
      emitUpdateNode(props.node.id, updates)
    }
  }

  return {
    switchConditionMode,
    updateComparison,
    updateValue,
    updateExtraComparison,
    updateFunction,
  }
}
