import {
  createConditionTreeEventForwarders,
  createConditionTreeListeners,
} from '../../shared/condition-tree-events'
import type { ConditionTreeEditorEmits } from './types'

interface SetupConditionTreeEditorBindingsOptions {
  emit: ConditionTreeEditorEmits
}

export function setupConditionTreeEditorBindings(options: SetupConditionTreeEditorBindingsOptions) {
  const forwarders = createConditionTreeEventForwarders(options.emit)
  const listeners = createConditionTreeListeners({ forwarders })

  return {
    listeners,
  }
}
