import type { ValueInputControllerState } from './useValueInputController.shared'
import type { useValueInputControllerActions } from './useValueInputController.actions'

export function createValueInputControllerExposedState(
  state: ValueInputControllerState,
  actions: ReturnType<typeof useValueInputControllerActions>,
) {
  return {
    selectedFunctionName: state.functionRefController.selectedFunctionName,
    functionParameters: state.functionRefController.functionParameters,
    functionCategories: state.functionRefController.functionCategories,
    selectedFunction: state.functionRefController.selectedFunction,
    dateValue: state.dateValue,
    multiValues: state.multiValues,
    urlError: state.urlError,
    getPlaceholder: state.getPlaceholder,
    isCompoundOperator: state.isCompoundOperator,
    getFieldTypeColor: state.getFieldTypeColor,
    getValueInputType: state.getValueInputType,
    getAvailableValueTypes: state.getAvailableValueTypes,
    getValueDataType: state.getValueDataType,
    getValueArrayIndex: state.getValueArrayIndex,
    getFieldTooltipForValue: state.getFieldTooltipForValue,
    updateValue: actions.updateValue,
    updateMultiValues: actions.updateMultiValues,
    updateDateValue: actions.updateDateValue,
    validateURL: actions.validateURL,
    changeValueDataType: actions.changeValueDataType,
    changeValueType: actions.changeValueType,
    updateBaseField: actions.updateBaseField,
    updateValueArrayIndex: actions.updateValueArrayIndex,
    updateFunction: actions.updateFunction,
    updateParameter: actions.updateParameter,
    generateFunctionExpression: actions.generateFunctionExpression,
  }
}
