import type { TreeNode } from '../../types'
import type { NodeInfo } from './types'

interface RestoreSourceNodeOptions {
  nodes: TreeNode[]
  sourceNode: TreeNode
  sourceResult: NodeInfo
}

export function restoreSourceNode(options: RestoreSourceNodeOptions) {
  const { nodes, sourceNode, sourceResult } = options

  if (sourceResult.parent) {
    if (!sourceResult.parent.children) sourceResult.parent.children = []
    sourceResult.parent.children.splice(sourceResult.index, 0, sourceNode)
    return
  }

  nodes.splice(sourceResult.index, 0, sourceNode)
}

interface DetachSourceNodeOptions {
  nodes: TreeNode[]
  sourceNodeId: string
  sourceResult: NodeInfo
}

export function detachSourceNode(options: DetachSourceNodeOptions) {
  const { nodes, sourceNodeId, sourceResult } = options

  if (sourceResult.parent) {
    sourceResult.parent.children = sourceResult.parent.children?.filter((node) => node.id !== sourceNodeId) || []
    return
  }

  const sourceRootIndex = nodes.findIndex((node) => node.id === sourceNodeId)
  if (sourceRootIndex >= 0) {
    nodes.splice(sourceRootIndex, 1)
  }
}

interface InsertSourceNodeInsideTargetOptions {
  sourceNode: TreeNode
  targetNode: TreeNode
}

export function insertSourceNodeInsideTarget(options: InsertSourceNodeInsideTargetOptions) {
  const { sourceNode, targetNode } = options

  if (!targetNode.children) targetNode.children = []
  targetNode.children.push(sourceNode)
}

interface InsertSourceNodeRelativeToTargetOptions {
  nodes: TreeNode[]
  sourceNode: TreeNode
  targetNodeId: string
  targetResult: NodeInfo
  position: 'before' | 'after'
}

export function insertSourceNodeRelativeToTarget(options: InsertSourceNodeRelativeToTargetOptions) {
  const { nodes, sourceNode, targetNodeId, targetResult, position } = options

  const targetParent = targetResult.parent
  const targetIndex = targetResult.index
  const insertIndex = position === 'before' ? targetIndex : targetIndex + 1

  if (targetParent) {
    if (!targetParent.children) targetParent.children = []
    targetParent.children.splice(insertIndex, 0, sourceNode)
    return
  }

  const rootTargetIndex = nodes.findIndex((node) => node.id === targetNodeId)
  const rootInsertIndex = position === 'before' ? rootTargetIndex : rootTargetIndex + 1
  nodes.splice(rootInsertIndex, 0, sourceNode)
}
