<template>
  <a-textarea
    v-if="isValueType"
    :model-value="param.value"
    :placeholder="textPlaceholder"
    :auto-size="{ minRows: 1, maxRows: 3 }"
    class="param-input-control"
    v-on="updateValueListeners"
  />

  <a-select
    v-else-if="isFieldType"
    :model-value="param.value"
    :placeholder="fieldPlaceholder"
    allow-search
    class="param-input-control"
    v-on="updateValueListeners"
  >
    <a-option
      v-for="field in availableFields"
      :key="field.value"
      :value="field.value"
      :label="field.label"
    >
      <span>{{ field.label }}</span>
    </a-option>
  </a-select>

  <a-textarea
    v-else
    :model-value="param.value"
    :placeholder="textPlaceholder"
    :auto-size="{ minRows: 1, maxRows: 3 }"
    class="param-input-control"
    v-on="updateValueListeners"
  />
</template>

<script setup lang="ts">
import type { FieldOption } from '../../../../../../infrastructure/engine/types'
import type { FunctionParameterItem } from '../types'
import {
  type FunctionRefParameterInputBodyEmits,
  useFunctionRefParameterInputBindings,
} from './useFunctionRefParameterInputBindings'

const props = defineProps<{
  param: FunctionParameterItem
  availableFields: FieldOption[]
}>()

const emit = defineEmits<FunctionRefParameterInputBodyEmits>()

const {
  updateValueListeners,
  fieldPlaceholder,
  textPlaceholder,
  isFieldType,
  isValueType,
} = useFunctionRefParameterInputBindings({
  props,
  emit,
})
</script>

<style scoped lang="scss">
.param-input-control {
  width: 150px;
}
</style>
