let globalDragListenersRefCount = 0
let hasGlobalDragListeners = false

export const clearAllTreeNodeDragStyles = () => {
  if (typeof document === 'undefined') return

  const allTreeNodes = document.querySelectorAll('.tree-node')
  allTreeNodes.forEach((node) => {
    const element = node as HTMLElement
    element.classList.remove('drag-over', 'drag-before', 'drag-after', 'drag-inside')

    const nodeContent = element.querySelector('.node-content') as HTMLElement | null
    if (nodeContent) {
      nodeContent.style.border = ''
      nodeContent.style.background = ''
      nodeContent.style.boxShadow = ''
    }
  })
}

const handleGlobalDragCleanup = () => {
  clearAllTreeNodeDragStyles()
}

export const ensureGlobalDragListeners = () => {
  if (typeof document === 'undefined') return

  if (!hasGlobalDragListeners) {
    document.addEventListener('dragend', handleGlobalDragCleanup)
    document.addEventListener('drop', handleGlobalDragCleanup)
    hasGlobalDragListeners = true
  }
  globalDragListenersRefCount += 1
}

export const releaseGlobalDragListeners = () => {
  if (typeof document === 'undefined') return

  globalDragListenersRefCount = Math.max(0, globalDragListenersRefCount - 1)
  if (globalDragListenersRefCount === 0 && hasGlobalDragListeners) {
    document.removeEventListener('dragend', handleGlobalDragCleanup)
    document.removeEventListener('drop', handleGlobalDragCleanup)
    hasGlobalDragListeners = false
  }
}
