import type { setupFunctionComparisonValueInputBindings } from './setup'

interface CreateFunctionComparisonValueInputExposedBindingsOptions {
  setupResult: ReturnType<typeof setupFunctionComparisonValueInputBindings>
}

export function createFunctionComparisonValueInputExposedBindings(
  options: CreateFunctionComparisonValueInputExposedBindingsOptions,
) {
  const { setupResult } = options

  return {
    valueInputListeners: setupResult.listeners.valueInputListeners,
  }
}
