import type { createTreeNodeViewForwarders } from '../useTreeNodeViewBindings.forwarders'
import type { createTreeNodeViewHandlers } from '../useTreeNodeViewBindings.handlers'
import type { createTreeNodeControllerBindings } from './controller'
import { createTreeNodeChildrenListeners } from './listeners.children'
import { createTreeNodeContentListeners } from './listeners.content'
import { createTreeNodeShellListeners } from './listeners.shell'

interface CreateTreeNodeViewListenersOptions {
  controller: ReturnType<typeof createTreeNodeControllerBindings>
  handlers: ReturnType<typeof createTreeNodeViewHandlers>
  forwarders: ReturnType<typeof createTreeNodeViewForwarders>
}

export function createTreeNodeViewListeners(options: CreateTreeNodeViewListenersOptions) {
  const { controller, handlers, forwarders } = options

  const shellListeners = createTreeNodeShellListeners(controller)
  const contentListeners = createTreeNodeContentListeners({
    controller,
    handlers,
    forwarders,
  })
  const childrenListeners = createTreeNodeChildrenListeners(forwarders)

  return {
    shellListeners,
    contentListeners,
    childrenListeners,
  }
}
