import { createTreeNodeDragHandlersExposed } from './exposed'
import { createTreeNodeDragLeaveHandler } from './leave'
import { createTreeNodeDragOverDropHandlers } from './over-drop'
import { createTreeNodeDragStartEndHandlers } from './start-end'
import type { UseTreeNodeDragHandlersOptions } from './types'

export type { UseTreeNodeDragHandlersOptions } from './types'

export function useTreeNodeDragHandlers(options: UseTreeNodeDragHandlersOptions) {
  const startEndHandlers = createTreeNodeDragStartEndHandlers({
    nodeId: options.nodeId,
    clearAllDragStates: options.clearAllDragStates,
  })
  const overDropHandlers = createTreeNodeDragOverDropHandlers(options)
  const leaveHandler = createTreeNodeDragLeaveHandler({
    clearDragState: options.clearDragState,
  })

  return createTreeNodeDragHandlersExposed({
    startEndHandlers,
    overDropHandlers,
    leaveHandler,
  })
}
