import { createConditionValueEditorExposedBindings } from './condition-value-bindings/exposed'
import { setupConditionValueEditorBindings } from './condition-value-bindings/setup'
import type { ConditionValueEditorEmits, ConditionValueEditorProps } from './condition-value-bindings/types'

export type { ConditionValueEditorEmits, ConditionValueEditorProps } from './condition-value-bindings/types'

interface UseConditionValueEditorBindingsOptions {
  props: ConditionValueEditorProps
  emit: ConditionValueEditorEmits
}

export function useConditionValueEditorBindings(options: UseConditionValueEditorBindingsOptions) {
  const setupResult = setupConditionValueEditorBindings(options)
  return createConditionValueEditorExposedBindings({ setupResult })
}
