import { getDefaultLambdaExpression } from '../logic/parameterInputValueTransitions'
import type {
  ParameterInputControllerState,
  UseParameterInputControllerActionsOptions,
} from './useParameterInputController.actions.shared'

export function createInitializeLambdaParameterAction(
  state: ParameterInputControllerState,
  options: UseParameterInputControllerActionsOptions,
) {
  const { props, emitUpdateValue } = options

  return () => {
    if (!state.isCurrentLambdaParameter()) {
      return
    }

    if (!props.value || props.value === '' || props.value === null || props.value === undefined) {
      state.userSelectedType.value = 'lambda'
      setTimeout(() => {
        emitUpdateValue(getDefaultLambdaExpression())
      }, 0)
    }
  }
}
