import type { FieldOption, NodeValue } from '../../infrastructure/engine/types'

const DEFAULT_LAMBDA_EXPRESSION = 'lambda(x) -> x.field == value end'

function isEmptyValue(value: NodeValue): boolean {
  return value === undefined || value === null || value === ''
}

export function resolveValueModeValue(params: {
  savedStringValue: string
  currentValue: NodeValue
}): NodeValue {
  const { savedStringValue, currentValue } = params
  const valueToRestore: NodeValue = savedStringValue

  if (isEmptyValue(valueToRestore)) {
    if (typeof currentValue === 'string' && currentValue.includes('lambda(')) {
      return `"${currentValue}"`
    }
    return currentValue || ''
  }

  if (typeof valueToRestore === 'string' && valueToRestore.trim() !== '') {
    if (valueToRestore === 'true' || valueToRestore === 'false') {
      return valueToRestore === 'true'
    }

    if (!Number.isNaN(Number(valueToRestore))) {
      return Number(valueToRestore)
    }
  }

  return valueToRestore
}

export function resolveFieldModeValue(currentValue: NodeValue, availableFields: readonly FieldOption[]): NodeValue {
  if (typeof currentValue === 'string' && availableFields.some((field) => field.value === currentValue)) {
    return currentValue
  }

  return availableFields.length > 0 ? availableFields[0].value : ''
}

export function resolveLambdaModeValue(currentValue: NodeValue): NodeValue {
  let lambdaValue: NodeValue = currentValue

  if (typeof currentValue === 'string'
    && ((currentValue.startsWith('"') && currentValue.endsWith('"'))
    || (currentValue.startsWith('\'') && currentValue.endsWith('\'')))) {
    lambdaValue = currentValue.slice(1, -1)
  }

  if (typeof lambdaValue !== 'string' || !lambdaValue.includes('lambda(')) {
    return DEFAULT_LAMBDA_EXPRESSION
  }

  return lambdaValue
}

export function getDefaultLambdaExpression(): string {
  return DEFAULT_LAMBDA_EXPRESSION
}
