import type { NodeValue } from '../../../../../../infrastructure/engine/types'
import type { ConditionValueInputSwitchEmits } from './types'

export function createConditionValueInputSwitchListeners(emit: ConditionValueInputSwitchEmits) {
  const valueListeners = {
    'update:model-value': (value: NodeValue) => emit('update:value', value),
  } as const

  const multiValueListeners = {
    'update:model-value': (value: string[]) => emit('update:multi-values', value),
  } as const

  const dateValueListeners = {
    'update:model-value': (value: Date | undefined) => emit('update:date-value', value),
  } as const

  const urlListeners = {
    'update:model-value': (value: NodeValue) => emit('update:value', value),
    'blur': () => emit('blur:url'),
  } as const

  const fallbackListeners = {
    'update:value': (value: NodeValue) => emit('update:value', value),
  } as const

  return {
    valueListeners,
    multiValueListeners,
    dateValueListeners,
    urlListeners,
    fallbackListeners,
  }
}
