import { computed } from 'vue'
import type { ConditionValueEditorProps } from './types'

interface ConditionValueEditorPanelState {
  isNullComparison: { value: boolean }
  isMultiValue: { value: boolean }
  multiValuePlaceholder: { value: string }
  multiValueTooltip: { value: string }
}

export function createConditionValueEditorPanelProps(
  props: ConditionValueEditorProps,
  state: ConditionValueEditorPanelState,
) {
  const valueInputSwitchProps = computed(() => ({
    value: props.value,
    fieldType: props.fieldType,
    valueDataType: props.valueDataType,
    isNullComparison: state.isNullComparison.value,
    isMultiValue: state.isMultiValue.value,
    multiValues: props.multiValues,
    multiValuePlaceholder: state.multiValuePlaceholder.value,
    multiValueTooltip: state.multiValueTooltip.value,
    placeholder: props.placeholder,
    urlError: props.urlError,
    dateValue: props.dateValue,
  }))

  const dataTypeSwitchProps = computed(() => ({
    modelValue: props.valueDataType,
  }))

  return {
    valueInputSwitchProps,
    dataTypeSwitchProps,
  }
}
