import { computed } from 'vue'
import type { ParameterInputProps } from '../../../composables/useParameterInputController'
import type { ParameterInputViewModelState } from './view-model.types'

interface CreateParameterInputSelectorViewModelOptions {
  props: ParameterInputProps
  state: ParameterInputViewModelState
}

export function createParameterInputSelectorViewModel(
  options: CreateParameterInputSelectorViewModelOptions,
) {
  const { props, state } = options

  const selectorKey = computed(
    () => `type-selector-${props.parameter.name}-${state.currentParameterInputType.value}`,
  )

  const selectorProps = computed(() => ({
    modelValue: state.currentParameterInputType.value,
    options: state.parameterTypeOptions.value,
    placeholder: '参数类型',
  }))

  return {
    selectorKey,
    selectorProps,
  }
}
