import { createFieldModeEditorExposedBindings } from './field-mode-editor-bindings/exposed'
import { setupFieldModeEditorBindings } from './field-mode-editor-bindings/setup'
import type { UseFieldModeEditorBindingsOptions } from './field-mode-editor-bindings/types'

export type {
  FieldModeEditorEmits,
  UseFieldModeEditorBindingsOptions,
} from './field-mode-editor-bindings/types'

export function useFieldModeEditorBindings(options: UseFieldModeEditorBindingsOptions) {
  const setupResult = setupFieldModeEditorBindings(options)
  return createFieldModeEditorExposedBindings({ setupResult })
}
